const allQuestionsPool = [
    // === 第1章 モバイルシステムの概要 (30問) ===
    { id: 101, chapter: 1, text: "モバイルシステムの構成要素のうち、スマートフォンやタブレット、センサーデバイスなどが該当する要素はどれですか。", options: ["モバイルネットワーク", "モバイル機器", "サーバ・固定ネットワーク", "モバイルアダプタ"], answer: 1, explain: "モバイルシステムは大きく「モバイル機器」「モバイルネットワーク」「サーバ・固定ネットワーク」の3つの要素で構成されます。" },
    { id: 102, chapter: 1, text: "モバイルシステムの構成要素のうち、基地局やコアネットワークを含み、無線と有線を仲介するインフラ部分はどれですか。", options: ["モバイル端末", "サーバ・固定ネットワーク", "モバイルネットワーク", "モバイルワイヤレスルータ"], answer: 2, explain: "モバイルネットワークは、無線アクセスネットワークとコアネットワークを含み、端末とサーバ間の通信を担います。" },
    { id: 103, chapter: 1, text: "モバイルシステムの構成において、業務アプリケーションやデータベースを保持し、基幹業務を行う部分はどれですか。", options: ["モバイル機器", "サーバ・固定ネットワーク", "モバイル接続機器", "情報収集端末"], answer: 1, explain: "サーバ・固定ネットワークは、モバイルネットワークを介して送られてきたデータを処理・蓄積する中枢部分です。" },
    { id: 104, chapter: 1, text: "モバイル端末の分類のうち、主にPCの機能に近い演算能力を持ち、OS上で多様なソフトウェアを実行する端末はどれに分類されますか。", options: ["情報通信端末", "表示視聴端末", "情報収集端末", "情報処理端末"], answer: 3, explain: "ノートPCやPDAなどは、高い演算能力とOSを備えた「情報処理端末」に分類されます。" },
    { id: 105, chapter: 1, text: "モバイル端末の分類のうち、スマートフォンやフィーチャーフォンなど、主に音声通話やメールによるコミュニケーションを主目的とした端末はどれですか。", options: ["情報通信端末", "情報収集端末", "表示視聴端末", "情報処理端末"], answer: 0, explain: "通話やメッセージ交換を中心とした端末は「情報通信端末」に分類されます。" },
    { id: 106, chapter: 1, text: "モバイル端末の分類のうち、電子書籍リーダーやデジタルフォトフレームなど、情報の閲覧に特化した端末はどれですか。", options: ["情報通信端末", "表示視聴端末", "情報処理端末", "情報収集端末"], answer: 1, explain: "主にコンテンツを見る・聴くことに特化したものは「表示視聴端末」です。" },
    { id: 107, chapter: 1, text: "モバイル端末の分類のうち、スマートメーターや監視カメラ、各種環境センサーなどはどれに分類されますか。", options: ["情報通信端末", "表示視聴端末", "情報収集端末", "情報処理端末"], answer: 2, explain: "周囲の環境データを取得し、自動で送信する端末は「情報収集端末」と呼ばれます。" },
    { id: 108, chapter: 1, text: "パソコンやスマートフォンなどのデバイス間で、データや通信信号を相互に変換・中継するための機器は何と呼びますか。", options: ["データ通信用モジュール", "モバイルワイヤレスルータ", "データ通信用アダプタ", "アクセスポイント"], answer: 2, explain: "外部から接続して通信機能を付加する機器を「データ通信用アダプタ」と呼びます。" },
    { id: 109, chapter: 1, text: "自動販売機や車両、決済端末などの機器の内部にあらかじめ組み込まれている通信用の電子部品を何と呼びますか。", options: ["データ通信用アダプタ", "データ通信用モジュール", "表示視聴端末", "モバイルネットワーク"], answer: 1, explain: "機器の筐体内に埋め込まれて(Embedded)使用されるものを「データ通信用モジュール」と呼びます。" },
    { id: 110, chapter: 1, text: "自身が基地局と接続し、周囲の複数のPCやゲーム機などをWi-Fi経由でインターネットに接続させる持ち運び可能な機器は何ですか。", options: ["情報通信端末", "モバイルネットワーク", "モバイルワイヤレスルータ", "データ通信用モジュール"], answer: 2, explain: "モバイルワイヤレスルータは、モバイル回線とWi-Fiなどの近距離無線を仲介するゲートウェイの役割を果たします。" },
    { id: 111, chapter: 1, text: "モバイル機器をネットワークに接続させるための「アダプタ」「モジュール」「ワイヤレスルータ」などの総称は何ですか。", options: ["モバイル端末", "モバイルネットワーク", "サーバ", "モバイル接続機器"], answer: 3, explain: "端末そのものではなく、通信機能を提供・拡張するための周辺機器を「モバイル接続機器」と総称します。" },
    { id: 112, chapter: 1, text: "モバイルシステムの課題において、端末を紛失した際に遠隔からデータを消去(リモートワイプ)することは、どの対策に該当しますか。", options: ["モバイル端末本体へのセキュリティ対策", "公衆無線LANを利用する際のセキュリティ対策", "組織内ネットワークのセキュリティ対策", "固定ネットワークのセキュリティ対策"], answer: 0, explain: "リモートワイプや画面ロック、生体認証などは、物理的なデバイスを守る「モバイル端末本体へのセキュリティ対策」です。" },
    { id: 113, chapter: 1, text: "不特定多数が利用するフリーWi-Fiにおいて、通信内容を盗み見られないようにVPNを利用することは、どの対策に該当しますか。", options: ["モバイル端末本体へのセキュリティ対策", "公衆無線LANを利用する際のセキュリティ対策", "組織内ネットワークのセキュリティ対策", "サーバ・固定ネットワークのセキュリティ対策"], answer: 1, explain: "公衆回線という信頼できない経路を通る際の暗号化などは「公衆無線LANを利用する際のセキュリティ対策」です。" },
    { id: 114, chapter: 1, text: "社内ネットワークへの不正侵入を防ぐため、ファイアウォールやIDSを設置することは、どの対策に該当しますか。", options: ["モバイル端末本体へのセキュリティ対策", "公衆無線LANを利用する際のセキュリティ対策", "組織内ネットワークのセキュリティ対策", "モバイル接続機器のセキュリティ対策"], answer: 2, explain: "モバイルシステムから送られてきたデータを受け入れる側の防御は「組織内ネットワークのセキュリティ対策」です。" },
    { id: 115, chapter: 1, text: "モバイル端末の定義として、最も適切なものはどれですか。", options: ["常に電源コードで接続されているデスクトップPC", "無線通信機能を持ち、人が持ち運んで移動しながら利用できる電子機器", "建物に固定された基地局アンテナ", "通信事業者の局舎内に設置されたサーバ"], answer: 1, explain: "持ち運びが可能(ポータブル)で、無線通信(ワイヤレス)を利用できることがモバイル端末の基本要件です。" },
    { id: 116, chapter: 1, text: "「モバイルシステム」の導入メリットとして、不適切なものはどれですか。", options: ["場所を選ばずリアルタイムに情報共有ができる", "業務効率化やコスト削減につながる", "端末の紛失による情報漏洩リスクが完全にゼロになる", "迅速な意思決定が可能になる"], answer: 2, explain: "モバイルシステムの導入により利便性は上がりますが、紛失等の新たなセキュリティリスクが発生するため、対策が必要です。" },
    { id: 117, chapter: 1, text: "モバイルネットワークを介して企業のサーバにアクセスする際、接続先情報を指定するために設定する値の略称は何ですか。", options: ["PIN", "APN", "IMEI", "MAC"], answer: 1, explain: "APN(アクセスポイント名)は、どのネットワークの出口(サーバ)へ向かうかを指定する設定値です。" },
    { id: 118, chapter: 1, text: "情報収集端末の一種で、水道・ガス・電気などの使用量を自動的に検針するシステムの名称は何ですか。", options: ["スマートメーター", "スマートルータ", "デジタルブック", "モジュールアダプタ"], answer: 0, explain: "スマートメーターはmMTC(多数同時接続)の代表例であり、情報収集端末の典型的なユースケースです。" },
    { id: 119, chapter: 1, text: "モバイル端末本体へのセキュリティ対策として、OSやアプリを最新の状態に保つ理由は何ですか。", options: ["バッテリーの持ちを良くするため", "通信速度を10倍にするため", "脆弱性(セキュリティ上の欠陥)を修正するため", "画面の解像度を上げるため"], answer: 2, explain: "OSやアプリの更新には、発見された脆弱性を塞ぐパッチが含まれているため、最新状態を保つことが重要です。" },
    { id: 120, chapter: 1, text: "組織内ネットワークのセキュリティ対策において、社外から社内ネットワークへ安全に接続するための仮想的な専用線の仕組みを何と呼びますか。", options: ["WWW", "FTP", "VPN", "HTTP"], answer: 2, explain: "VPN(Virtual Private Network:仮想専用線)を利用することで、公衆網を通るデータでも暗号化されたトンネルによって安全に接続できます。" },
    { id: 121, chapter: 1, text: "表示視聴端末の例として、正しい組み合わせはどれですか。", options: ["スマートフォン、フィーチャーフォン", "電子書籍リーダー、デジタルサイネージ", "監視カメラ、スマートメーター", "ノートPC、PDA"], answer: 1, explain: "情報の閲覧・表示に主眼を置くものが表示視聴端末です。1は情報通信、3は情報収集、4は情報処理に該当します。" },
    { id: 122, chapter: 1, text: "データ通信用アダプタとデータ通信用モジュールの最大の違いは何ですか。", options: ["通信速度が全く異なる", "アダプタは外付け機器、モジュールは内蔵電子部品である", "アダプタは有線専用、モジュールは無線専用である", "利用できるキャリアが制限される"], answer: 1, explain: "アダプタはUSB等で取り外し可能(外付け)、モジュールは基板等に実装(内蔵)という物理的な形態の違いが定義の核です。" },
    { id: 123, chapter: 1, text: "公衆無線LANのセキュリティ課題として、「なりすましアクセスポイント」があります。これへの対策として適切なものはどれですか。", options: ["画面の明るさを最大にする", "接続時に表示されるSSIDが正しいものか確認し、信頼できないWi-Fiには繋がない", "端末のRAM容量を増やす", "常にテザリングをONにしておく"], answer: 1, explain: "偽のWi-Fi(なりすまし)に接続すると通信内容を窃取される恐れがあるため、提供元を確認することが基本です。" },
    { id: 124, chapter: 1, text: "モバイルシステムの概要における「サーバ・固定ネットワーク」の主な役割はどれですか。", options: ["電波を端末へ放射する", "モバイル端末を物理的に保護する", "端末から送られてきた情報の加工・蓄積や業務処理を行う", "端末のバッテリーを充電する"], answer: 2, explain: "システムのバックエンドとして、情報の処理・保管を担います。" },
    { id: 125, chapter: 1, text: "近年増加している「M2M」通信において、中心的な役割を果たす端末分類はどれですか。", options: ["情報通信端末", "表示視聴端末", "情報収集端末", "翻訳端末"], answer: 2, explain: "機械同士(M2M)の通信では、センサーやメーターなどの「情報収集端末」から自動でデータが送信されるケースが大半です。" },
    { id: 126, chapter: 1, text: "モバイル端末を組織(企業)で利用する際、全端末を一括管理してセキュリティ設定を強制する仕組みを何と呼びますか。", options: ["APNマネジメント", "MDM", "LTE", "CMOS"], answer: 1, explain: "MDM(モバイルデバイス管理)は、企業のセキュリティポリシーを一律に適用するためのシステムです。" },
    { id: 127, chapter: 1, text: "モバイルシステムのセキュリティ対策のうち、「ウイルス対策ソフトの導入」はどの分類に該当しますか。", options: ["モバイル端末本体へのセキュリティ対策", "公衆無線LANを利用する際のセキュリティ対策", "組織内ネットワークのセキュリティ対策", "インフラ設備のセキュリティ対策"], answer: 0, explain: "端末内にインストールして守るソフトは「端末本体への対策」に含まれます。" },
    { id: 128, chapter: 1, text: "情報通信端末の特徴として、適切な記述はどれですか。", options: ["常に固定電話と同じ場所に設置する必要がある", "移動しながらの双方向コミュニケーションを主目的としている", "動画を再生する機能しか持たない", "インターネットには一切接続できない"], answer: 1, explain: "電話やメールなど、場所を問わず通信(コミュニケーション)することを主目的とした端末です。" },
    { id: 129, chapter: 1, text: "第1章の「モバイルシステムの概要」において、今後さらなる普及が期待されている、あらゆるモノがネットに繋がる概念を何と呼びますか。", options: ["MVNO", "IoT", "BBU", "C-RAN"], answer: 1, explain: "Internet of Thingsは、本章で解説された多様な端末分類や収集端末の普及によって、モバイルシステムの核となる概念です。" },
    { id: 130, chapter: 1, text: "モバイルシステムにおいて、端末とサーバ間の通信を担う中核的なインフラ部分はどれか。", options: ["モバイル機器", "モバイルネットワーク", "情報収集端末", "固定ネットワーク"], answer: 1, explain: "モバイルネットワークは、無線アクセス網とコア網から構成され、端末とサーバを繋ぎます。" },

    // === 第2章 移動体通信サービス (30問) ===
    { id: 201, chapter: 2, text: "1979年に開始された自動車電話サービスで採用されていた通信方式と、1993年に開始された携帯電話サービスで採用された通信方式の変遷として正しいものはどれか。", options: ["アナログ方式からデジタル方式へ移行した", "デジタル方式からアナログ方式へ移行した", "パケット方式から回線交換方式へ移行した", "アナログ方式のまま周波数のみが変更された"], answer: 0, explain: "日本の移動体通信は、1979年にアナログ方式の自動車電話サービスから始まり、1993年にデジタル携帯サービスへと移行することで、通信品質の向上や秘話性の確保が実現しました。" },
    { id: 202, chapter: 2, text: "1999年に国内でサービスが開始され、携帯電話の画面からウェブサイトの閲覧や電子メールの送受信を可能にした画期的なサービスの総称はどれか。", options: ["モバイルインターネットサービス", "インターネット電話", "国際ローミング", "ショートメッセージサービス"], answer: 0, explain: "NTTドコモの「iモード」などに代表されるモバイルインターネットサービスが登場したことで、携帯電話は単なる電話機から情報通信端末へと大きく進化しました。" },
    { id: 203, chapter: 2, text: "4G世代の技術発展によって実現し、モバイル環境での大容量コンテンツのやり取りを飛躍的に向上させた通信速度の指標として最も適切なものはどれか。", options: ["最大100Kbpsのデータ通信", "最大1Mbpsのデータ通信", "最大1Gbpsの高速データ通信", "最大100Gbpsの高速データ通信"], answer: 2, explain: "4GのLTE-Advancedなどの技術導入により、最大1Gbpsの高速データ通信が実現し、動画ストリーミングなどのリッチコンテンツが快適に利用できるようになりました。" },
    { id: 204, chapter: 2, text: "5Gの特徴を示すキーワードのうち、4Kや8Kといった高精細な動画のストリーミング再生や、大容量ファイルの瞬時なダウンロードに直結する要件はどれか。", options: ["多数同時接続", "超高速", "超高信頼・低遅延", "モバイルインターネット"], answer: 1, explain: "5Gの3大要件の1つである「超高速」は、広帯域な周波数の活用などによって実現され、従来のモバイル通信の常識を覆す大容量データの送受信を可能にします。" },
    { id: 205, chapter: 2, text: "5Gの特徴を示すキーワードのうち、自動運転車両のリアルタイム制御や、遠隔地からの精密な医療手術ロボットの操作などに不可欠とされる要件はどれか。", options: ["多数同時接続", "超高速", "超高信頼・低遅延", "回線交換方式"], answer: 2, explain: "5Gの「超高信頼・低遅延」は、通信のタイムラグを極限まで減らし、かつパケットロスを防ぐ要件であり、人命や安全に関わるシビアな用途で求められます。" },
    { id: 206, chapter: 2, text: "5Gの特徴を示すキーワードのうち、スマートメーターや環境センサーなど、1平方キロメートルあたり100万台規模の膨大なIoT機器をネットワークに収容するための要件はどれか。", options: ["多数同時接続", "超高速", "超高信頼・低遅延", "事業者間ローミング"], answer: 0, explain: "5Gの「多数同時接続」により、身の回りのあらゆるモノがインターネットに繋がるIoT社会のインフラが支えられています。" },
    { id: 207, chapter: 2, text: "従来の3Gまでの音声通話で主に用いられていた、発信者と着信者の間に専用の経路を確立し、通信が終了するまでその回線を占有し続ける通信方式はどれか。", options: ["パケット通信", "インターネット電話", "回線交換方式", "モバイルネットワーク"], answer: 2, explain: "回線交換方式は、通話中に帯域を占有するため通信品質は安定しますが、ネットワークの利用効率という面ではパケット通信に劣ります。" },
    { id: 208, chapter: 2, text: "データを細切れのまとまりに分割し、それぞれに宛先情報を付与してネットワーク上に送り出すことで、複数のユーザーで回線を共有できる効率的な通信方式はどれか。", options: ["アナログ方式", "回線交換方式", "パケット通信", "FMC"], answer: 2, explain: "パケット通信は、データをパケットと呼ばれる単位に分割して送受信するため、1つの回線を多数のユーザーで効率よく共有できます。" },
    { id: 209, chapter: 2, text: "音声信号をデジタルデータ化し、IPネットワーク上でリアルタイムに送受信する通信技術の総称はどれか。", options: ["VoIP", "SMS", "RCS", "GNSS"], answer: 0, explain: "VoIP(Voice over Internet Protocol)は、インターネットなどのIPネットワークを使って音声通話を実現する技術の基盤です。" },
    { id: 210, chapter: 2, text: "VoIP技術の1つであり、無料通話アプリなどのようにインターネット網を経由して提供され、通信の品質保証が厳密に行われない形式の通話サービスはどれか。", options: ["回線交換方式", "インターネット電話", "IP移動電話サービス", "キャリアメール"], answer: 1, explain: "インターネット電話は、公衆インターネットを経由するため通話料が無料または安価ですが、ネットワークの混雑状況によって通話品質が低下する場合があります。例:LINE、Zoom" },
    { id: 211, chapter: 2, text: "LTEネットワーク上で音声通話を実現する技術であり、音声をデジタルデータに変換してパケット通信網でやり取りするIP移動電話サービスはどれか。", options: ["VoLTE", "インターネット電話", "アナログ方式", "Webメール"], answer: 0, explain: "VoLTE(Voice over LTE)は、IP電話サービスの一種ですが、キャリアの閉域網で厳密な品質保証(QoS)が行われるため、高音質で安定した通話が可能です。" },
    { id: 212, chapter: 2, text: "電話番号を宛先として、他社の携帯電話宛にも短いテキストメッセージを送受信できるサービスはどれか。", options: ["SMS", "Webメール", "電子メール", "キャリアメール"], answer: 0, explain: "SMSは、電話番号だけで確実にメッセージを届けることができるため、二段階認証のコード送信などにも広く利用されています。" },
    { id: 213, chapter: 2, text: "SMSを発展させ、長文や高解像度の画像、グループチャット、既読確認などを可能にしたGSMA標準のメッセージングサービス規格はどれか。", options: ["VoLTE", "RCS", "FMC", "LEO"], answer: 1, explain: "RCS(Rich Communication Services)は、従来のSMSの制限をなくした次世代のメッセージ規格であり、国内キャリアの「＋メッセージ」などに採用されています。" },
    { id: 214, chapter: 2, text: "パソコンなどで広く使われるメールの仕組みであり、特定のプロバイダに依存せずインターネットプロトコルを用いてテキストやファイルを送受信する通信手段の総称はどれか。", options: ["SMS", "RCS", "電子メール", "インターネット電話"], answer: 2, explain: "電子メール(E-mail)は、SMTPやPOP3、IMAP4などのプロトコルを使用してメッセージをやり取りする最も基本的なインターネットサービスです。" },
    { id: 215, chapter: 2, text: "移動体通信事業者が自社のスマートフォンや携帯電話の契約者に対して提供し、高い信頼性を備えた電子メールのサービス形態はどれか。", options: ["キャリアメール", "Webメール", "SMS", "VoIP"], answer: 0, explain: "キャリアメールは、通信事業者独自のドメイン(@docomo.ne.jpなど)を持ち、迷惑メールフィルタなどの機能が充実しています。" },
    { id: 216, chapter: 2, text: "キャリアメールの優れた特徴であり、サーバにメールが届いた際、ユーザーが自分で問い合わせなくても端末に自動で新着通知や本文が送られてくる配信方式はどれか。", options: ["プッシュ型", "プル型", "パケット通信", "回線交換方式"], answer: 0, explain: "プッシュ型配信により、ユーザーはリアルタイムにメールの着信に気づくことができます。" },
    { id: 217, chapter: 2, text: "ブラウザから専用サイトにアクセスして電子メールの送受信を行う形態であり、端末にデータを保存しないため複数の異なる端末からのアクセスに便利なものはどれか。", options: ["キャリアメール", "Webメール", "RCS", "ショートメッセージサービス"], answer: 1, explain: "Webメールは、クラウド上のサーバにメールデータが保存されるため、スマートフォンやPCなどどの端末からでも同じメールボックスを管理できます。" },
    { id: 218, chapter: 2, text: "ユーザーが操作するスマートフォンやタブレットなどの機器そのものを指す用語はどれか。", options: ["モバイル端末", "モバイルネットワーク", "モバイルインターネット", "サーバ"], answer: 0, explain: "モバイル端末は、無線通信を利用して情報を処理・表示する利用者の手元の機器を指します。" },
    { id: 219, chapter: 2, text: "モバイル端末をインターネット等の固定ネットワークへ繋ぐために、基地局やコア設備などで構成される中継インフラを何と呼ぶか。", options: ["モバイルネットワーク", "モバイル端末", "Webメール", "FMC"], answer: 0, explain: "モバイルネットワークは、無線区間を管理するアクセス網と、データ転送や認証を行うコア網で構成されます。" },
    { id: 220, chapter: 2, text: "モバイル端末とモバイルネットワークを利用して、移動中や外出先からインターネット上のさまざまなサービスを利用する環境を総称して何と呼ぶか。", options: ["モバイルインターネット", "国際ローミング", "キャリアメール", "GNSS"], answer: 0, explain: "モバイルインターネットは、私たちが日々スマートフォンでウェブを閲覧したりアプリを利用したりする環境全体を指す言葉です。" },
    { id: 221, chapter: 2, text: "契約している通信事業者のサービスエリア外である海外へ渡航した際、現地の提携通信事業者の設備を利用して、自分の電話番号のまま通信できるサービスはどれか。", options: ["事業者間ローミング", "国際ローミング", "SIMロック解除", "FMC"], answer: 1, explain: "国際ローミングにより、海外の空港に降り立った瞬間から普段通りにスマートフォンで通信を行うことができます。" },
    { id: 222, chapter: 2, text: "災害時や自社エリア外において、国内の他の移動体通信事業者のネットワークを利用して通信を継続する仕組みはどれか。", options: ["事業者間ローミング", "国際ローミング", "インターネット電話", "MNO"], answer: 0, explain: "事業者間ローミング(国内ローミング)は、通信障害時や過疎地でのカバレッジ補完として重要な仕組みです。" },
    { id: 223, chapter: 2, text: "1つの端末で、外出先ではモバイル通信網を、オフィスや自宅では固定通信網と無線LANをシームレスに切り替えて利用するなど、固定通信と移動通信を融合させたサービス形態はどれか。", options: ["FMC", "RCS", "GNSS", "NTN"], answer: 0, explain: "FMC(Fixed Mobile Convergence)は、利用者がネットワークの違いを意識することなく、常に最適な通信環境を利用できるようにする概念です。" },
    { id: 224, chapter: 2, text: "アメリカのGPSや日本の準天頂衛星みちびきなど、複数の測位衛星から受信した信号をもとに現在位置を高精度に算出するシステムの総称はどれか。", options: ["GNSS", "NTN", "HAPS", "FMC"], answer: 0, explain: "GNSS(Global Navigation Satellite System)は、スマートフォンの地図アプリや位置情報サービスに不可欠な全地球測位システムです。" },
    { id: 225, chapter: 2, text: "基地局の電波が届かない海上や山岳地帯をカバーするため、人工衛星などを利用して地上から空や宇宙へと通信エリアを拡張する非地上系ネットワークの略称はどれか。", options: ["NTN", "LEO", "GEO", "HAPS"], answer: 0, explain: "NTN(Non-Terrestrial Network)は、地上のインフラに依存せず、地球上のあらゆる場所を通信エリア化する次世代のネットワーク構想です。" },
    { id: 226, chapter: 2, text: "衛星通信に用いられる人工衛星のうち、高度数百キロメートルから数千キロメートルの軌道を周回し、通信遅延が比較的小さいため次世代の通信サービスで主役となっているものはどれか。", options: ["LEO", "GEO", "HAPS", "GNSS"], answer: 0, explain: "LEO(Low Earth Orbit:低軌道衛星)は地球からの距離が近いため、従来の静止衛星と比較して遅延が少なく、スマートフォンとの直接通信の実現に向けて活用されています。" },
    { id: 227, chapter: 2, text: "衛星通信に用いられる人工衛星のうち、高度約3万6000キロメートルの赤道上空を地球の自転と同じ周期で周回し、地上から常に同じ位置にあるように見える衛星はどれか。", options: ["GEO", "LEO", "HAPS", "NTN"], answer: 0, explain: "GEO(Geostationary Earth Orbit:静止軌道衛星)は、1機の衛星で地球の広範囲をカバーできますが、地球からの距離が遠いため通信遅延が大きくなる特徴があります。" },
    { id: 228, chapter: 2, text: "成層圏に無人航空機などを長期間滞空させ、上空から広範囲の地上エリアに通信サービスを提供する高高度プラットフォームシステムの略称はどれか。", options: ["HAPS", "GNSS", "LEO", "GEO"], answer: 0, explain: "HAPS(High Altitude Platform Station)は、空飛ぶ基地局として、災害時の迅速なエリア復旧や離島の通信確保に期待されています。" },
    { id: 229, chapter: 2, text: "自社で物理的な無線通信インフラを持たず、他の事業者からネットワークを借り受けて独自の通信サービスを提供する事業者はどれか。", options: ["MVNO", "MNO", "FMC", "RCS"], answer: 0, explain: "仮想移動体通信事業者であるMVNOは、設備投資を抑えることができるため、安価な料金プランなどの独自サービスを展開しています。" },
    { id: 230, chapter: 2, text: "端末を購入した通信事業者のSIMカードでしか通信できないようにする制限を解除し、他社のSIMカードでも利用可能にする手続きを何と呼ぶか。", options: ["SIMロック解除", "国際ローミング", "事業者間ローミング", "パケット通信"], answer: 0, explain: "SIMロック解除を行うことで、利用者は自身の端末をそのまま使いながら、用途に合わせて通信事業者(MNOやMVNO)を自由に選択できるようになります。" },

    // === 第3章 無線アクセスネットワーク技術 (32問) ===
    { id: 301, chapter: 3, text: "モバイルネットワークにおいて、端末と直接電波のやり取りを行う基地局などで構成されるネットワーク部分を何と呼ぶか。", options: ["RAN", "CN", "IMS", "ISP"], answer: 0, explain: "RANは無線アクセスネットワークの略称で、スマートフォンと電波で通信を行うアンテナや基地局の設備群を指します。" },
    { id: 302, chapter: 3, text: "RANからのデータを受け取り、端末の認証やルーティングなどの通信制御を行う中枢のネットワーク部分を何と呼ぶか。", options: ["RAN", "CN", "RU", "BBU"], answer: 1, explain: "CNはコアネットワークの略称で、モバイル通信システムの頭脳にあたる交換機やデータベース群で構成されます。" },
    { id: 303, chapter: 3, text: "送信したい音声やデータなどの情報信号を、空間に飛ばしやすい高い周波数の電波に乗せるための変換操作を何と呼ぶか。", options: ["復調", "変調", "符号化", "多重化"], answer: 1, explain: "変調を行うことで、アンテナから効率よく電波として放射できる周波数帯の信号に変換します。" },
    { id: 304, chapter: 3, text: "受信した高い周波数の電波から、もとの音声やデータなどの情報信号を取り出す操作を何と呼ぶか。", options: ["変調", "復調", "暗号化", "圧縮"], answer: 1, explain: "復調は変調の逆の操作であり、電波から元の情報データを取り出すためのプロセスです。" },
    { id: 305, chapter: 3, text: "電波の送信と受信の両方を行う機器において、変調と復調の両方の機能を兼ね備えた回路や装置を総称して何と呼ぶか。", options: ["ルータ", "変復調", "スイッチ", "アダプタ"], answer: 1, explain: "変調と復調の両方を行う機器は、それぞれの英語名の頭文字をとってモデムとも呼ばれます。" },
    { id: 306, chapter: 3, text: "情報信号の電圧の変化をそのまま電波の振幅や周波数の連続的な変化として送る方式と、情報を0と1のデータに変換してから電波に乗せる方式の組み合わせとして正しいものはどれか。", options: ["空間ダイバーシティとMIMO", "アナログ変調とデジタル変調", "FDMAとTDMA", "NSAとSA"], answer: 1, explain: "連続的な波のまま送るのがアナログ変調、0と1の不連続なデータに変換して送るのがデジタル変調です。現在はノイズに強いデジタル変調が主流です。" },
    { id: 307, chapter: 3, text: "送信するデジタルデータにあらかじめ規則性のある余分なデータを付加し、受信側で電波のノイズによるデータの誤りを検知して自動的に修復する技術を何と呼ぶか。", options: ["ARQ", "適応変調", "誤り訂正符号化", "ビームフォーミング"], answer: 2, explain: "誤り訂正符号化により、多少のノイズでデータが破損しても再送することなく受信側で自己修復できるため、通信の効率が向上します。" },
    { id: 308, chapter: 3, text: "誤り訂正符号化を使っても修復できないデータエラーが発生した場合に、受信側が送信側に対してエラーデータの再送を自動的に要求する仕組みを何と呼ぶか。", options: ["ARQ", "MIMO", "ハンドオーバー", "セルラー方式"], answer: 0, explain: "ARQは自動再送要求の略称で、誤り訂正符号化と組み合わせて使用されることで、無線の信頼性を極めて高く保ちます。" },
    { id: 309, chapter: 3, text: "端末の移動による電波状態の変化に合わせて、一度に送るデータ量と誤りへの強さのバランスをとり、最適な変調方式をリアルタイムに切り替える技術を何と呼ぶか。", options: ["適応変調", "空間ダイバーシティ", "フロントホール", "バックホール"], answer: 0, explain: "適応変調により、基地局の近くで電波が良いときは情報量の多い変調方式を使い、遠くで電波が悪いときはエラーに強い変調方式に動的に変更します。" },
    { id: 310, chapter: 3, text: "建物などに反射した複数の電波が異なる経路を通って受信アンテナに到達し、互いに干渉し合って受信信号の強度が激しく変動する現象を何と呼ぶか。", options: ["遠近問題", "マルチパスフェージング", "ハンドオーバー", "サイクリックプリフィックス"], answer: 1, explain: "マルチパスフェージングは、直接届く電波と反射して遅れて届く電波がぶつかり合うことで発生する、モバイル通信特有の課題です。" },
    { id: 311, chapter: 3, text: "マルチパスフェージングによる遅延波の干渉を防ぐため、送信する信号の末尾の一部分を先頭にコピーして挿入するガード区間を何と呼ぶか。", options: ["サイクリックプリフィックス", "フロントホール", "バックホール", "アクセス方式"], answer: 0, explain: "サイクリックプリフィックスというのりしろを設けることで、遅れて届いた電波が次のデータに被って干渉するのを防ぐことができます。" },
    { id: 312, chapter: 3, text: "受信側で複数のアンテナを空間的に離して配置し、最も状態の良いアンテナからの信号を選択したり合成したりして通信品質を安定させる技術を何と呼ぶか。", options: ["ビームフォーミング", "空間ダイバーシティ", "OFDMA", "CDMA"], answer: 1, explain: "空間ダイバーシティは、マルチパスフェージングによる電波の落ち込みを防ぎ、通信を切れにくくするためのアンテナ技術です。" },
    { id: 313, chapter: 3, text: "送信側と受信側の双方が複数のアンテナを使用し、同じ周波数帯で同時に異なるデータを空間的に多重化して送受信することで、通信速度を飛躍的に高める技術を何と呼ぶか。", options: ["MIMO", "ARQ", "誤り訂正符号化", "適応変調"], answer: 0, explain: "MIMOは複数のアンテナを束ねて通信経路を増やす技術であり、4Gや5Gの高速化に欠かせない中核技術です。" },
    { id: 314, chapter: 3, text: "多数のアンテナ素子から送信する電波の位相を精密に制御し、特定の端末がある方向へ電波を集中させて放射することで、通信距離の延長や干渉の低減を図る技術を何と呼ぶか。", options: ["ビームフォーミング", "ハンドオーバー", "セルラー方式", "遠近問題"], answer: 0, explain: "ビームフォーミングは電波を特定の方向に絞り込んで照射する技術であり、直進性が高く減衰しやすい5Gの高周波数帯などで特に威力を発揮します。" },
    { id: 315, chapter: 3, text: "基地局の近くにいる端末が強い電波を送信すると、遠くにいる端末の微弱な電波がかき消されてしまう現象を何と呼ぶか。", options: ["マルチパスフェージング", "遠近問題", "サイクリックプリフィックス", "空間ダイバーシティ"], answer: 1, explain: "遠近問題を解決するために、基地局は端末の送信電力を必要最低限に抑えさせる送信電力制御を行っています。" },
    { id: 316, chapter: 3, text: "サービスエリアを多数の小さな六角形などの区画に分割し、それぞれの区画に基地局を配置して、離れた区画では同じ周波数を再利用することで多数のユーザーを収容する方式を何と呼ぶか。", options: ["セルラー方式", "アクセス方式", "MIMO", "フロントホール"], answer: 0, explain: "セルラー方式によって、限られた周波数資源を使い回すことができ、全国規模の広大な通信エリアを構築することが可能になります。" },
    { id: 317, chapter: 3, text: "端末が通信を行いながら移動し、接続する基地局のエリアをまたぐ際に、通信を切断することなく次の基地局へと接続を切り替える技術を何と呼ぶか。", options: ["セルラー方式", "ビームフォーミング", "ハンドオーバー", "ARQ"], answer: 2, explain: "ハンドオーバーにより、高速で移動する自動車や電車の中であっても通話やデータ通信が途切れることなく継続されます。" },
    { id: 318, chapter: 3, text: "基地局の設備構成のうち、アンテナのすぐ近くに設置され、デジタル信号とアナログの高周波信号の変換および電力増幅を担う無線ユニットを何と呼ぶか。", options: ["CN", "CU", "DU", "RU"], answer: 3, explain: "RUは無線ユニットの略称で、アンテナの直下や一体型として設置され、実際の電波の送受信を担います。" },
    { id: 319, chapter: 3, text: "5Gの基地局構成において、高度なデータ処理や制御を行う集約ユニットと、リアルタイム性の高い無線信号処理を行う分散ユニットに機能分割されたそれぞれの略称の組み合わせはどれか。", options: ["CNとRAN", "RUとMIMO", "CUとDU", "NSAとSA"], answer: 2, explain: "CUは集約ユニット、DUは分散ユニットを指します。基地局機能をこれらに分割することで、柔軟で効率的なネットワーク構築が可能になりました。" },
    { id: 320, chapter: 3, text: "基地局の分散ユニットと無線ユニットを結ぶネットワーク区間、および基地局とコアネットワークを結ぶネットワーク区間の組み合わせとして正しいものはどれか。", options: ["フロントホールとバックホール", "アップリンクとダウンリンク", "アナログ変調とデジタル変調", "FDMAとTDMA"], answer: 0, explain: "アンテナ側の区間をフロントホール、コアネットワーク側の区間をバックホールと呼び、どちらも光ファイバーなどで大容量通信を支えています。" },
    { id: 321, chapter: 3, text: "限られた電波の周波数帯を、複数のユーザーが互いに混信することなく効率的に共有して通信するための通信路の割り当て技術を総称して何と呼ぶか。", options: ["セルラー方式", "アクセス方式", "空間ダイバーシティ", "誤り訂正符号化"], answer: 1, explain: "アクセス方式には、周波数、時間、符号などを用いてユーザーを区別するためのさまざまな方式が存在します。" },
    { id: 322, chapter: 3, text: "周波数帯を細かな帯域に分割し、ユーザーごとに異なる周波数を割り当てることで複数の通信を同時に行うアクセス方式はどれか。", options: ["FDMA", "TDMA", "CDMA", "OFDMA"], answer: 0, explain: "FDMAは周波数分割多元接続の略で、アナログ自動車電話の時代から使われてきた基本的なアクセス方式です。" },
    { id: 323, chapter: 3, text: "同じ周波数帯を極めて短い時間で区切り、ユーザーごとに異なる時間枠を順番に割り当てることで複数の通信を同時に行うアクセス方式はどれか。", options: ["FDMA", "TDMA", "CDMA", "OFDMA"], answer: 1, explain: "TDMAは時分割多元接続の略で、第2世代のデジタル携帯電話などで広く採用されました。" },
    { id: 324, chapter: 3, text: "ユーザーごとに異なる特定の符号を割り当ててデータを拡散送信し、受信側で同じ符号を使って元のデータを取り出すことで、同じ周波数と時間を共有するアクセス方式はどれか。", options: ["FDMA", "TDMA", "CDMA", "OFDMA"], answer: 2, explain: "CDMAは符号分割多元接続の略で、第3世代移動通信システムの主流となったアクセス方式です。" },
    { id: 325, chapter: 3, text: "直交する多数のサブキャリアを時間と周波数のブロックに細分化し、複数のユーザーに柔軟に割り当てることで周波数利用効率を極限まで高めたアクセス方式はどれか。", options: ["FDMA", "TDMA", "CDMA", "OFDMA"], answer: 3, explain: "OFDMAは直交周波数分割多元接続の略で、4Gや5Gの下りリンクで採用されている高度なアクセス方式です。" },
    { id: 326, chapter: 3, text: "国際電気通信連合が定めた第3世代移動通信システムの国際標準規格の名称はどれか。", options: ["IMT-2000", "IMT-Advanced", "IMT-2020", "Beyond5G"], answer: 0, explain: "IMT-2000は、世界中で同じ端末が使えることを目指して標準化された第3世代の通信規格です。" },
    { id: 327, chapter: 3, text: "国際電気通信連合が定めた第4世代移動通信システムの国際標準規格の名称はどれか。", options: ["IMT-2000", "IMT-Advanced", "IMT-2020", "Beyond5G"], answer: 1, explain: "IMT-Advancedは、データ通信のさらなる高速化を目指した第4世代の通信規格です。" },
    { id: 328, chapter: 3, text: "国際電気通信連合が定めた第5世代移動通信システムの国際標準規格の名称はどれか。", options: ["IMT-2000", "IMT-Advanced", "IMT-2020", "Beyond5G"], answer: 2, explain: "IMT-2020は、2020年頃の実用化を目標に定められた第5世代の通信規格です。" },
    { id: 329, chapter: 3, text: "日本などで利用されていたAXGP方式が、国際的なエコシステムに合流するために互換性を持たせた4Gの通信規格はどれか。", options: ["CDMA2000", "W-CDMA", "TD-LTE互換", "NR"], answer: 2, explain: "TD-LTE互換方式を採用することで、世界中の多くの端末で利用可能なグローバルなネットワークに統合されました。" },
    { id: 330, chapter: 3, text: "5Gで新たに規定された、超高速や低遅延などの高度な要求を満たすための新しい無線アクセス技術の規格名称はどれか。", options: ["OFDMA", "NR", "LTE", "MIMO"], answer: 1, explain: "NRは5Gのための新しい無線インターフェース規格であり、周波数帯の柔軟な利用などを実現しています。" },
    { id: 331, chapter: 3, text: "5Gの導入初期において、既存の4Gコアネットワークと4G基地局を制御に利用しつつ、データ通信に5G基地局を追加して連携させる非独立型のネットワーク構成はどれか。", options: ["NSA", "SA", "RAN", "CN"], answer: 0, explain: "NSA構成を採用することで、通信事業者は既存の4G設備を活用しながら迅速に5Gエリアを展開することができました。" },
    { id: 332, chapter: 3, text: "4Gの設備を利用せず、5G専用のコアネットワークと5G基地局のみで構成し、高速・低遅延・多数接続を実現する高度な無線アクセスや機能分割をフルに発揮できる独立型のネットワーク構成はどれか。", options: ["NSA", "SA", "Beyond5G", "TD-LTE互換"], answer: 1, explain: "SA構成により、ネットワークスライシングなどの5G本来の革新的な機能が提供可能になります。次世代のBeyond5Gに向けても重要な基盤となります。" },
    { id: 333, chapter: 14, text: "無線通信において「広い周波数帯（広帯域）」を使用する最大の目的は何ですか。", options: ["電波の到達距離を極限まで延ばすため", "一度に送受信できるデータ量（通信容量）を増やすため", "障害物による減衰を完全に無くすため", "免許不要で誰でも利用できるようにするため"], answer: 1, explain: "広い周波数帯は一度に運べる情報量を増やすためのものであり、高速・大容量通信を実現するために不可欠です。" },
    { id: 334, chapter: 14, text: "周波数が「高い」電波の物理的な特性として、適切なものはどれですか。", options: ["障害物を回り込む性質（回折）が非常に強い", "電波の直進性が強く、遠くまで届きにくい", "低い周波数よりも広範囲を一度にカバーできる", "波長が非常に長く、アンテナを大型化する必要がある"], answer: 1, explain: "高い周波数の電波は直進性が強く、障害物に弱いため、到達距離が短くなる傾向があります。" },
    { id: 335, chapter: 14, text: "5Gのミリ波帯などで高い周波数帯を用いる主な理由は何ですか。", options: ["広帯域を確保しやすく、超高速・大容量通信を実現できるため", "山間部などの過疎地を効率的にカバーできるため", "他の通信機器と干渉が発生しないため", "基地局を減らしてコストを削減できるため"], answer: 0, explain: "高い周波数帯ほど空き帯域を確保しやすく、圧倒的な情報量を扱えるため高速通信に適しています。" },
    { id: 336, chapter: 14, text: "高い周波数帯で使われる、狙った方向にだけ電波を集中させて放射する技術を何と呼びますか。", options: ["周波数ホッピング", "ビームフォーミング", "適応変調", "空間ダイバーシティ"], answer: 1, explain: "ビームフォーミングは複数のアンテナから電波を合成し、特定の端末に向けて電波を束ねる技術です。" },
    { id: 337, chapter: 14, text: "移動中でも繋がる安定性を重視する場合、通常どの周波数帯が好んで使われますか。", options: ["高い周波数帯", "低い周波数帯", "極めて広い帯域幅を持つミリ波帯", "専用線による有線接続のみ"], answer: 1, explain: "低い周波数帯は障害物を回り込む能力が高く、広域をカバーするのに適しています。" },
    { id: 338, chapter: 14, text: "「周波数帯が広い」ことと「周波数が高い」ことの違いとして、最も適切な説明はどれですか。", options: ["広いとは周波数の範囲のことであり、高いとは波長が短いことである", "高いとは周波数の範囲が広いことであり、広いとは周波数そのものが高いことである", "両者は全く同じ意味であり、使い分ける必要はない", "周波数帯が広いほど、電波は遠くまで届きやすくなる"], answer: 0, explain: "広い(広帯域)は帯域幅の大きさ、高いは周波数そのものの値（＝波長が短い）を指します。" },
    { id: 339, chapter: 14, text: "人が密集するスタジアム等で、特定のスポットのみ大容量通信を実現するために適した電波の特徴はどれですか。", options: ["低い周波数帯で広域をカバーする", "高い周波数帯でビームフォーミングを用いる", "帯域幅を極限まで狭くして混信を防ぐ", "障害物を極限まで透過する電波を利用する"], answer: 1, explain: "高い周波数は局所的に大容量を確保でき、ビームフォーミングで各ユーザーを狙い撃ちできます。" },
    { id: 340, chapter: 14, text: "無線通信において、低い周波数帯が「障害物に強い」とされる物理的な理由はどれですか。", options: ["低い周波数ほど回折（障害物を回り込む）現象が起きやすいため", "低い周波数ほど空気抵抗を受けないため", "低い周波数帯ほど光に近い速度で進むため", "低い周波数帯ほど基地局から常に強く発信されているため"], answer: 0, explain: "周波数が低い（波長が長い）ほど、障害物の裏側に電波が回り込む性質が強くなります。" },
    { id: 341, chapter: 14, text: "モバイルネットワークで「広い周波数帯域」を確保するための手法で、複数の周波数帯を束ねる手法を何と呼びますか。", options: ["キャリアアグリゲーション", "ハンドオーバー", "マルチパスフェージング", "ビームフォーミング"], answer: 0, explain: "キャリアアグリゲーションは複数の帯域を束ねて、1つの広い帯域のように扱う技術です。" },
    { id: 342, chapter: 14, text: "モバイル通信において「高い周波数帯」のデメリットとして適切なものはどれですか。", options: ["他の機器と干渉しないため、制御が複雑になる", "減衰しやすく、基地局を密に設置する必要がある", "アンテナが大きくなり、端末が重くなる", "一度に送れるデータ量が非常に少ない"], answer: 1, explain: "高い周波数は障害物に弱く減衰しやすいため、広範囲をカバーするには多くの基地局が必要です。" },

    // === 第4章 コアネットワーク技術 (33問) ===
    { id: 401, chapter: 4, text: "4Gで採用された、音声通話を含めすべての通信をパケット通信で統合して処理するコアネットワークの構成を何と呼ぶか。", options: ["アナログ構成", "ALL-IP構成", "回線交換構成", "SBA構成"], answer: 1, explain: "ALL-IP構成により、音声通話もIPパケットとして処理されるようになり、ネットワークの効率化と運用コストの削減が実現しました。" },
    { id: 402, chapter: 4, text: "3GPPで標準化された、LTEにおけるALL-IPベースのコアネットワークの名称はどれか。", options: ["EPC", "MEC", "RAN", "SBA"], answer: 0, explain: "EPCはLTE向けのコアネットワークであり、すべてIPベースでパケット処理を行うよう設計されています。" },
    { id: 403, chapter: 4, text: "EPCにおいて、端末の移動管理や認証などの制御プレーンの処理を担当するノードはどれか。", options: ["S-GW", "P-GW", "MME", "HSS"], answer: 2, explain: "MMEは、端末の位置情報管理や認証、セッションの確立など、制御にかかわるシグナリングを専門に行います。" },
    { id: 404, chapter: 4, text: "EPCにおいて、基地局とコアネットワークの間に位置し、ユーザーデータの転送処理を担うノードはどれか。", options: ["MME", "HSS", "P-GW", "S-GW"], answer: 3, explain: "S-GWは基地局からのユーザーデータを収容し、外部ネットワークへの出入り口であるP-GWへとパケットを中継・転送します。" },
    { id: 405, chapter: 4, text: "EPCにおいて、インターネットなどの外部パケットネットワークとの接続点となり、IPアドレスの割り当てやルーティングを行うゲートウェイはどれか。", options: ["S-GW", "P-GW", "MME", "UPF"], answer: 1, explain: "P-GWは外部ネットワークとの境界に位置し、パケットのルーティングやフィルタリング、IPアドレスの払い出しを行います。" },
    { id: 406, chapter: 4, text: "モバイルネットワークにおいて、ユーザーの契約情報や電話番号、認証のための暗号鍵などを一元管理しているデータベースはどれか。", options: ["MME", "HSS", "S-GW", "IMS"], answer: 1, explain: "HSSにはユーザーが正当な契約者であるかを確認するための重要なマスターデータが格納されています。" },
    { id: 407, chapter: 4, text: "オールIP化されたモバイルネットワーク上で、VoLTEなどの音声通話やマルチメディアセッションを制御する共通基盤システムはどれか。", options: ["IMS", "EPC", "SBA", "NPN"], answer: 0, explain: "IMSはIPネットワーク上でセッションを確立するシステムで、音声パケットを優先して送るなどの品質制御もこの基盤で行われます。" },
    { id: 408, chapter: 4, text: "5Gコアネットワークで採用された、ネットワーク機能を細分化されたサービスの集合体として定義し、柔軟に組み合わせて構成するアーキテクチャを何と呼ぶか。", options: ["ALL-IPパケット交換コアネットワーク", "EPC", "SBA", "NFV"], answer: 2, explain: "SBAを採用することで、各ネットワーク機能が独立したサービスとして通信し合うようになり、柔軟な機能追加や拡張が可能になりました。" },
    { id: 409, chapter: 4, text: "5GのSBAにおいて、各ネットワーク機能間の通信プロトコルとして採用されているWeb標準技術はどれか。", options: ["FTP", "HTTP/2", "SMTP", "POP3"], answer: 1, explain: "IT業界で広く使われているHTTP/2およびRESTベースのAPIを採用することで、ネットワーク構築の柔軟性と開発効率が向上しました。" },
    { id: 410, chapter: 4, text: "1つの物理的なネットワークをソフトウェア技術によって論理的に分割し、用途に合わせた独立の仮想ネットワークを提供する技術はどれか。", options: ["キャリアアグリゲーション", "ネットワークスライシング", "ビームフォーミング", "LTEデータローミング"], answer: 1, explain: "ネットワークスライシングにより、自動運転用の低遅延網や動画配信用の大容量網など、要件の異なるサービスを同一インフラ上で同時に提供できます。" },
    { id: 411, chapter: 4, text: "企業や自治体などが特定のエリア内に独自の5Gネットワークを構築するローカル5Gやプライベート5Gなどの、非パブリックネットワークを指す用語はどれか。", options: ["NPN", "MNP", "TSN", "SBA"], answer: 0, explain: "NPNは特定の企業や組織が専有するネットワークであり、通信事業者が提供する公衆網から独立して高いセキュリティと安定性を確保できます。" },
    { id: 412, chapter: 4, text: "端末に近いネットワークの末端側にサーバーを配置し、データ処理を行うことでクラウドまでの通信遅延を極小化する技術はどれか。", options: ["NFV", "MEC", "SDN", "CNF"], answer: 1, explain: "MECを導入することで、データが遠くのコアネットワークまで往復する時間が省かれ、自動運転などの超低遅延サービスが実現します。" },
    { id: 413, chapter: 4, text: "5Gネットワークにおいて、ネットワークの各種データを収集および解析し、その結果を用いてネットワークの最適化や自動制御を行う技術はどれか。", options: ["ネットワークデータ解析", "ナンバーポータビリティ", "ネットワークスライシング", "リダイレクション方式"], answer: 0, explain: "ネットワークデータ解析機能を活用することで、トラフィックの予測やリソースの動的割り当てなど、AIを用いた高度なネットワーク運用が可能になります。" },
    { id: 414, chapter: 4, text: "5Gにおいて工場内の産業用ロボット制御などで求められる、時刻同期と低遅延・高信頼性をイーサネット上で実現するための規格群はどれか。", options: ["SBA", "LBO", "TSN", "HTTP/2"], answer: 2, explain: "TSNと5Gシステムを連携させることで、工場の製造ラインなどにおいて有線LANに匹敵する安定した無線通信が実現します。" },
    { id: 415, chapter: 4, text: "5Gコアネットワークにおいて、EPCのS-GWやP-GWのユーザーデータ転送機能を統合し、パケットのルーティングや転送に特化したノードはどれか。", options: ["AMF", "SMF", "UPF", "HSS"], answer: 2, explain: "UPFはデータプレーンの処理に特化しており、制御機能から完全に分離されているため、MEC環境の構築などに柔軟に対応できます。" },
    { id: 416, chapter: 4, text: "端末の電源を入れた際などに、ネットワークに接続要求を送り、正当な端末としての認証を受けて位置登録を完了させる最初の手続きを何と呼ぶか。", options: ["アタッチ", "デタッチ", "ローミング", "ハンドオーバー"], answer: 0, explain: "アタッチが完了することで、ネットワーク側は端末がどのエリアにいるかを把握でき、通信や着信が可能になります。" },
    { id: 417, chapter: 4, text: "端末の電源を切る際やネットワークから切り離される際に、ネットワーク上の位置登録情報や通信セッションを解放する手続きを何と呼ぶか。", options: ["アタッチ", "デタッチ", "ページング", "スケジューリング"], answer: 1, explain: "デタッチを行うことでネットワークリソースが正しく解放され、無駄なリソースの消費を防ぐことができます。" },
    { id: 418, chapter: 4, text: "LTEや5Gにおいて、アタッチ完了と同時にデフォルトのIPアドレスが割り当てられ、常にパケット通信が可能な状態を維持する仕組みを何と呼ぶか。", options: ["Always ON", "フルローミング", "ナンバーポータビリティ", "ネットワークスライシング"], answer: 0, explain: "Always ONの仕組みにより、端末はユーザーが特別な操作をしなくても常にインターネットに繋がった状態を維持し、プッシュ通知などを受け取れます。" },
    { id: 419, chapter: 4, text: "自国の通信事業者のサービスエリア外である海外へ渡航した際、現地の提携通信事業者の設備を利用してデータ通信を行う仕組みはどれか。", options: ["LTEデータローミング", "L3接続", "緊急通報ローミング", "NPN"], answer: 0, explain: "LTEデータローミングにより、海外でもSIMカードを差し替えることなく、国内と同じようにスマートフォンで通信できます。" },
    { id: 420, chapter: 4, text: "LTEデータローミングにおいて、訪問先ネットワークのS-GWと、ホームネットワークのP-GWとの間を結ぶローミング用のインターフェースはどれか。", options: ["S1", "S5", "S8", "X2"], answer: 2, explain: "S8インターフェースを介して訪問先の国から自国のP-GWまでパケットが転送される方式が一般的であり、これをホームルーティング方式と呼びます。" },
    { id: 421, chapter: 4, text: "国際ローミングにおいて、ユーザーのデータ通信を自国まで戻さず、訪問先ネットワークのゲートウェイから直接インターネットへ抜ける方式を何と呼ぶか。", options: ["フルローミング", "リダイレクション方式", "転送方式", "LBO"], answer: 3, explain: "LBOはデータ転送の遅延を抑えるメリットがありますが、課金やサービス制御が複雑になるため、VoLTEローミングなどで活用されます。" },
    { id: 422, chapter: 4, text: "通信障害時や自社エリア外において、国内の他の移動体通信事業者のネットワークを利用して通信を継続する仕組みはどれか。", options: ["国際ローミング", "事業者間ローミング", "フルローミング", "NPN"], answer: 1, explain: "事業者間ローミングは国内ローミングとも呼ばれ、特定のキャリアで大規模障害が発生した際などの救済措置として重要視されています。" },
    { id: 423, chapter: 4, text: "事業者間ローミングの方式のうち、音声通話やデータ通信など、ホームネットワークで提供されているすべてのサービスをローミング先でも利用可能にする方式を何と呼ぶか。", options: ["フルローミング", "緊急通報ローミング", "LBO", "リダイレクション方式"], answer: 0, explain: "フルローミングはユーザーにとって利便性が高い反面、事業者間のシステム連携や精算の仕組みが複雑になります。" },
    { id: 424, chapter: 4, text: "事業者間ローミングにおいて、通信障害などの非常時に、110番や119番などの特定の宛先への発信のみを他社ネットワーク経由で可能にする方式はどれか。", options: ["フルローミング", "緊急通報ローミング", "L3接続", "L2接続"], answer: 1, explain: "緊急通報ローミングは、システム連携を最小限に抑えつつ、人命に関わる通信を最優先で確保するための仕組みです。" },
    { id: 425, chapter: 4, text: "携帯電話会社を変更しても、同じ電話番号を継続して利用できる制度を何と呼ぶか。", options: ["ナンバーポータビリティ", "ローミング", "アタッチ", "デタッチ"], answer: 0, explain: "ナンバーポータビリティを利用することで、ユーザーは電話番号が変わる不便を被ることなく、自由に通信キャリアを乗り換えることができます。" },
    { id: 426, chapter: 4, text: "ナンバーポータビリティにおいて、発信側の網から一旦番号の移転前の網に接続し、そこからデータベースの情報を元に移転先の網へ接続をやり直す方式はどれか。", options: ["転送方式", "リダイレクション方式", "LBO", "SBA"], answer: 1, explain: "リダイレクション方式は、移転前のネットワークが正しい移転先を教え、発信側がそれに従ってルートを引き直す手法です。" },
    { id: 427, chapter: 4, text: "ナンバーポータビリティにおいて、発信側の網から一旦番号の移転前の網に接続し、そこから移転先の網へそのまま経路を伸ばして接続する方式はどれか。", options: ["リダイレクション方式", "転送方式", "フルローミング", "L3接続"], answer: 1, explain: "転送方式は、移転前のネットワークが中継地点となって移転先へそのまま通信を転送する手法です。" },
    { id: 428, chapter: 4, text: "MVNOの接続方式のうち、ネットワーク層で接続し、主要なパケット管理装置もすべてMNO側のインフラに依存するため、低い初期投資で手軽に事業参入できる方式はどれか。", options: ["L2接続", "L3接続", "緊急通報ローミング", "事業者間ローミング"], answer: 1, explain: "L3接続はルータレベルのシンプルな接続であり、MNOの仕様に依存するため独自サービスの自由度は低くなります。" },
    { id: 429, chapter: 4, text: "MVNOがMNOの設備と接続する際、データリンク層で相互接続し、MVNO側が自前でパケット管理装置などを設置して独自のサービス設計を行う方式はどれか。", options: ["L3接続", "L2接続", "NPN", "MEC"], answer: 1, explain: "L2接続は初期投資が必要ですが、MVNO独自の速度制御やカウントフリーなどの独自サービスを提供することが可能になります。" },
    { id: 430, chapter: 4, text: "これまで専用のハードウェアで構成されていたルータや交換機などの機能を、汎用のサーバー上で動作するソフトウェアとして実装する技術はどれか。", options: ["NFV", "SDN", "TSN", "SBA"], answer: 0, explain: "NFVを導入することで、専用機器に依存しない柔軟なネットワークインフラの構築と運用コストの削減が可能になります。" },
    { id: 431, chapter: 4, text: "ネットワークの構成や設定を、物理的な配線変更ではなくソフトウェアによる制御で動的に変更および集中管理する技術はどれか。", options: ["NFV", "SDN", "LBO", "MNP"], answer: 1, explain: "SDNはネットワークをソフトウェアで定義・制御する技術であり、NFVと組み合わせることで次世代の柔軟なコアネットワークが実現します。" },
    { id: 432, chapter: 4, text: "仮想化技術を発展させ、アプリケーションを動作させるために必要なライブラリや設定ファイルなどをひとまとめにし、OS上で軽量かつ高速に動作させる仮想化の単位を何と呼ぶか。", options: ["コンテナ", "サーバー", "ノード", "ゲートウェイ"], answer: 0, explain: "コンテナは従来の仮想マシンよりも起動が早くリソース消費も少ないため、5Gコアネットワークの柔軟な構築に欠かせない技術です。" },
    { id: 433, chapter: 4, text: "5Gコアネットワークなどで採用されている、ネットワーク機能をコンテナ化して実装し、柔軟な拡張やデプロイを可能にするソフトウェアアーキテクチャを何と呼ぶか。", options: ["CNF", "L3接続", "EPC", "HSS"], answer: 0, explain: "CNFはクラウドネイティブなアプローチであり、スケジューリングツールなどと連携して、ネットワーク機能の自動的な拡張や修復を可能にします。" },
    { id: 434, chapter: 4, text: "LTEデータローミングにおいて、在圏網のS-GWとホーム網のP-GWを結ぶインターフェースはどれか。", options: ["S1", "S5", "S8", "S6a"], answer: 2, explain: "S8インターフェースは、ローミング時に訪問先網とホーム網のゲートウェイ間を接続するために使用されます。"},
    { id: 435, chapter: 4, text: "MMEとHSSの関係性について、正しい説明はどれか。", options: ["MMEはパケットの転送を担当し、HSSは認証を担当する", "MMEは加入者情報を保持し、HSSは無線リソースを管理する", "MMEは位置登録や認証を行い、HSSは加入者情報を保持する", "両者ともパケットの転送のみを行う"], answer: 2, explain: "MMEは制御プレーンの処理（認証・位置管理）を行い、HSSは加入者DBとして情報を保持します。"},
    { id: 436, chapter: 4, text: "モバイルネットワークにおいて、障害時にシステムが自律的に状況を検知し、復旧させる機能を何と呼ぶか。", options: ["マニュアルリカバリ", "ヒーリング", "プロビジョニング", "負荷分散のみ"], answer: 1, explain: "ヒーリングは、ネットワークの可用性を高めるための自動化技術です。"},

    // === 第5章 インターネット基盤技術 (30問) ===
    { id: 501, chapter: 5, text: "インターネットにおいて、事実上の標準として世界中で利用されている通信プロトコルの体系はどれか。", options: ["OSI参照モデル", "TCP/IP", "SNA", "IPX/SPX"], answer: 1, explain: "TCP/IPは、インターネットを構築するための通信プロトコル群の総称であり、現在のコンピュータネットワークにおけるデファクトスタンダード(事実上の標準)です。" },
    { id: 502, chapter: 5, text: "インターネットで利用される技術の標準化を行い、RFCと呼ばれる技術文書を発行している組織はどれか。", options: ["IEEE", "ITU-T", "IETF", "W3C"], answer: 2, explain: "IETFは、インターネットで利用されるTCP/IPなどのプロトコルの標準化を推進する国際的な組織です。" },
    { id: 503, chapter: 5, text: "異なるメーカーの機器間でも通信ができるように、ネットワークの機能を7つの階層に分けて定義した国際標準モデルはどれか。", options: ["TCP/IPプロトコルセット", "OSI参照モデル", "IEEE802規格", "CSMA/CD"], answer: 1, explain: "OSI参照モデルは、通信に必要な機能を物理層からアプリケーション層までの7つの階層に分類し、それぞれの役割を明確にしたモデルです。" },
    { id: 504, chapter: 5, text: "インターネットの通信機能を「ネットワークインターフェース層」「インターネット層」「トランスポート層」「アプリケーション層」の4階層で定義したものはどれか。", options: ["TCP/IPプロトコルセット", "OSI参照モデル", "ルーティングアーキテクチャ", "DNS階層モデル"], answer: 0, explain: "TCP/IPプロトコルセットは、OSI参照モデルよりもシンプルで実用的な4階層モデルを採用しています。" },
    { id: 505, chapter: 5, text: "ネットワーク機器のうち、受信した電気信号を増幅・整形し、受信したポート以外のすべてのポートへそのまま転送する物理層の機器はどれか。", options: ["スイッチングハブ", "ルータ", "リピータハブ", "ゲートウェイ"], answer: 2, explain: "リピータハブはOSI参照モデルの第1層(物理層)で動作し、届いた信号をそのまま全てのポートにコピーして送信するシンプルな集線装置です。" },
    { id: 506, chapter: 5, text: "ネットワーク機器のうち、受信したデータの宛先MACアドレスを読み取り、該当する機器が接続されているポートにのみデータを転送する機器はどれか。", options: ["リピータハブ", "ルータ", "スイッチングハブ", "モデム"], answer: 2, explain: "スイッチングハブ(ブリッジとも呼ばれます)は第2層(データリンク層)で動作し、MACアドレスを学習して無駄なデータ送信(衝突)を防ぎます。" },
    { id: 507, chapter: 5, text: "ネットワーク機器に割り当てられる固有のMACアドレスにおいて、前半の24ビットが表しているベンダー識別子を何と呼ぶか。", options: ["OUI", "IPアドレス", "サブネットマスク", "ポート番号"], answer: 0, explain: "OUIはIEEEが管理・割り当てを行っているベンダー(メーカー)固有の識別番号であり、MACアドレスの前半部分を構成します。" },
    { id: 508, chapter: 5, text: "有線LANの通信規格において、データの送信前にケーブルの空き状態を確認し、データが衝突した場合はランダムな時間待機してから再送するアクセス制御方式はどれか。", options: ["CSMA/CA", "CSMA/CD", "FDMA", "TDMA"], answer: 1, explain: "CSMA/CDは、イーサネット(有線LAN)で採用されている通信制御方式であり、通信の衝突を「検知」して対処します。" },
    { id: 509, chapter: 5, text: "CSMA/CD方式において、データの衝突を検知した後に各端末が再送するまでの待機時間をランダムに決定し、連続的な衝突を回避するアルゴリズムを何と呼ぶか。", options: ["ラウンドロビン", "バックオフアルゴリズム", "トークンパッシング", "スケジューリング"], answer: 1, explain: "バックオフアルゴリズムによって再送のタイミングをばらけさせることで、同じ端末同士が再び同時に送信して衝突するのを防ぎます。" },
    { id: 510, chapter: 5, text: "無線LANの通信規格において、電波の衝突を物理的に検出することが難しいため、送信前に一定時間待機して回線が空いているかを確認し、衝突を未然に回避するアクセス制御方式はどれか。", options: ["CSMA/CA", "CSMA/CD", "CDMA", "OFDMA"], answer: 0, explain: "無線LANでは有線のように衝突の確実な検知が難しいため、衝突を回避(Avoidance)するためのCSMA/CA方式が採用されています。" },
    { id: 511, chapter: 5, text: "TCP/IPのインターネット層およびOSI参照モデルのネットワーク層が担う最も主要な役割はどれか。", options: ["物理的なケーブルの電気信号を制御する", "隣接する機器との間でエラーのないデータ転送を行う", "異なるネットワークを相互に結び、最終的な宛先までデータを届ける", "アプリケーションに応じたデータの表現形式を変換する"], answer: 2, explain: "ネットワーク層プロトコルの役割は、IPアドレスを用いて複数の異なるネットワークをまたぎ、送信元から最終目的地(エンドツーエンド)まで通信経路を確立することです。" },
    { id: 512, chapter: 5, text: "ネットワーク上で、宛先IPアドレスをもとに最適な通信経路を選択してデータを中継する処理を何と呼ぶか。", options: ["スイッチング", "ルーティング", "カプセル化", "フラッディング"], answer: 1, explain: "ルーティング(経路制御)は、ネットワーク間の交差点でパケットの行き先を判断し、バケツリレーのように目的地へ届けるための重要な処理です。" },
    { id: 513, chapter: 5, text: "異なるネットワーク同士を接続し、ルーティングを行ってデータを中継するネットワーク層の機器はどれか。", options: ["リピータハブ", "スイッチングハブ", "ルータ", "ブリッジ"], answer: 2, explain: "ルータはOSI参照モデルの第3層(ネットワーク層)で動作し、IPアドレスを解釈してネットワーク間の経路選択を行います。" },
    { id: 514, chapter: 5, text: "ルータなどのネットワーク機器によって論理的に分割された、ブロードキャストが届く範囲であるひとまとまりのネットワークを何と呼ぶか。", options: ["セグメント", "ドメイン", "OUI", "ポート"], answer: 0, explain: "セグメントはルータによって区切られたネットワークの単位であり、不要なデータが他のネットワークに流れるのを防ぐ役割があります。" },
    { id: 515, chapter: 5, text: "ネットワークに接続された機器を識別するために、ネットワーク層で割り当てられる論理的なアドレスはどれか。", options: ["MACアドレス", "IPアドレス", "メールアドレス", "OUI"], answer: 1, explain: "IPアドレスは、ネットワーク上での住所にあたる論理アドレスであり、ルーティングにおいて目的地を特定するために使用されます。" },
    { id: 516, chapter: 5, text: "現在広く利用されているIPアドレスの規格のうち、アドレス長が32ビットで構成されているものはどれか。", options: ["IPv4", "IPv6", "MACアドレス", "ドメイン名"], answer: 0, explain: "IPv4は32ビットのアドレス空間を持ち、約43億個のIPアドレスを割り当てることができます。" },
    { id: 517, chapter: 5, text: "IPv4アドレスの枯渇問題を解決するために開発され、アドレス長が128ビットで構成されている規格はどれか。", options: ["IPv4", "IPv5", "IPv6", "IPv8"], answer: 2, explain: "IPv6は128ビットの長さを持つため、事実上無限に近い数のIPアドレスを割り当てることが可能になり、IoT機器の急増にも対応できます。" },
    { id: 518, chapter: 5, text: "トランスポート層のプロトコルのうち、通信相手とのコネクションを確立し、データの到達確認や再送制御を行うことで、信頼性の高い通信を実現するものはどれか。", options: ["UDP", "TCP", "IP", "ICMP"], answer: 1, explain: "TCPは、Webサイトの閲覧やファイルのダウンロードなど、データが1ビットでも欠けると困る確実な通信に用いられます。" },
    { id: 519, chapter: 5, text: "トランスポート層のプロトコルのうち、コネクションの確立や到達確認を行わず、信頼性よりも処理の高速性やリアルタイム性を重視するものはどれか。", options: ["TCP", "UDP", "HTTP", "FTP"], answer: 1, explain: "UDPはエラー制御の処理を省いているため高速であり、途中で一部のデータが欠けても問題が少ない音声通話や動画ストリーミングなどで用いられます。" },
    { id: 520, chapter: 5, text: "人が覚えやすいドメイン名と、コンピュータが処理するIPアドレスを相互に変換するインターネット上のシステムはどれか。", options: ["DNS", "DHCP", "NAT", "ARP"], answer: 0, explain: "DNSを利用することで、ユーザーは数字の羅列であるIPアドレスを意識することなく、ドメイン名でWebサイトなどにアクセスできます。" },
    { id: 521, chapter: 5, text: "インターネット上で、HTMLなどで記述されたWebページをハイパーリンクで結びつけ、ブラウザで閲覧できるようにしたシステムの総称はどれか。", options: ["WWW", "DNS", "SMTP", "IMAP"], answer: 0, explain: "WWW(World Wide Web)はインターネット上で最も普及している情報システムであり、HTTPというプロトコルを使用してデータをやり取りします。" },
    { id: 522, chapter: 5, text: "インターネットにおいて、電子メールを送信者の端末からメールサーバへ送る際や、メールサーバ間で転送する際に使用されるプロトコルはどれか。", options: ["POP3", "IMAP", "SMTP", "HTTP"], answer: 2, explain: "SMTPはメールを送信・転送するための標準プロトコルです。宛先のサーバに届くまでのバケツリレーを担います。" },
    { id: 523, chapter: 5, text: "電子メールを受信するプロトコルのうち、メールをサーバ上に保存したまま端末から閲覧・管理でき、複数の端末で同じメールボックスを同期するのに適しているものはどれか。", options: ["POP3", "IMAP", "SMTP", "DHCP"], answer: 1, explain: "IMAPはサーバ上でメールを管理するため、スマートフォンやPCなど複数の端末から同じ既読状態やフォルダ分けを確認するのに便利です。" },
    { id: 524, chapter: 5, text: "インターネットなどのIPネットワークを利用して、音声データをパケット化し、リアルタイムに送受信する技術の総称はどれか。", options: ["VoIP", "WebRTC", "WWW", "RTSP"], answer: 0, explain: "VoIPはVoice over IPの略であり、IP電話やVoLTE、各種通話アプリなど、現在の音声通信の基盤技術となっています。" },
    { id: 525, chapter: 5, text: "インターネット上で動画や音声のストリーミング配信を行う際、再生、一時停止、早送りなどの制御コマンドをやり取りするために使用されるプロトコルはどれか。", options: ["RTSP", "SMTP", "DNS", "IMAP"], answer: 0, explain: "RTSPはリアルタイムなメディアストリームの制御を行うためのプロトコルであり、実際のメディアデータの転送にはRTPなどの別のプロトコルが使われます。" },
    { id: 526, chapter: 5, text: "特別なプラグインや専用ソフトをインストールすることなく、Webブラウザのみで音声通話やビデオ通話などのリアルタイム通信を実現するオープン標準技術はどれか。", options: ["WebRTC", "RTSP", "VoIP", "DNS"], answer: 0, explain: "WebRTCはHTML5の技術要素として標準化されており、ブラウザ同士が直接通信(P2P)を行って低遅延な通話を可能にします。" },
    { id: 527, chapter: 5, text: "送信元のアプリケーションと宛先のアプリケーションを識別するために、TCPやUDPのヘッダに含まれる番号を何と呼ぶか。", options: ["IPアドレス", "MACアドレス", "ポート番号", "OUI"], answer: 2, explain: "IPアドレスが「建物の住所」だとすれば、ポート番号はその中にある「部屋番号(どのアプリケーションへ届けるか)」を示す役割を持っています。" },
    { id: 528, chapter: 5, text: "TCPにおいて、データ通信を開始する前に送信側と受信側の間で3回のパケットのやり取りを行い、論理的な通信路を確立する手順を何と呼ぶか。", options: ["バックオフアルゴリズム", "スリーウェイハンドシェイク", "ルーティング", "スイッチング"], answer: 1, explain: "TCPはスリーウェイハンドシェイクによって確実な通信の準備を行ってから、実際のデータの送受信を開始します。" },
    { id: 529, chapter: 5, text: "データリンク層の中継機器であるブリッジと同じ役割を持ち、MACアドレスを学習して不要なデータの衝突を防ぐ集線装置の別名はどれか。", options: ["スイッチングハブ", "リピータハブ", "ルータ", "ゲートウェイ"], answer: 0, explain: "スイッチングハブは内部でブリッジとしての働きを持っており、宛先MACアドレスに対応する特定のポートにのみデータを流すことができます。" },
    { id: 530, chapter: 5, text: "有線LANのCSMA/CDと無線LANのCSMA/CAの違いについて、最も適切な記述はどれか。", options: ["CSMA/CDは衝突を回避する方式であり、CSMA/CAは衝突を検知する方式である。", "CSMA/CDは衝突を検知して再送する方式であり、CSMA/CAは送信前に待機して衝突を未然に回避する方式である。", "CSMA/CDは無線LAN専用であり、CSMA/CAは有線LAN専用である。", "CSMA/CDはルータで動作し、CSMA/CAはリピータハブで動作する。"], answer: 1, explain: "有線LANは電気的に衝突(Collision Detection)を検知できますが、無線LANは電波の性質上検知が難しいため、事前に回避(Collision Avoidance)する仕組みをとっています。" },
    { id: 531, chapter: 5, text: "AS内部でルーティング情報を交換するために使用されるプロトコルの総称はどれか。", options: ["EGP", "IGP", "DNS", "ARP"], answer: 1, explain: "IGPは、組織内のルータ同士で経路情報を交換するために設計されたプロトコルです。" },
    { id: 532, chapter: 5, text: "AS間を接続し、組織間やプロバイダ間で経路情報を交換するために使用されるプロトコルはどれか。", options: ["IGP", "EGP", "ICMP", "HTTP"], answer: 1, explain: "EGPは、インターネット全体におけるネットワーク境界を越えた経路制御を担うプロトコルの総称です。" },
    { id: 533, chapter: 5, text: "インターネットのAS間ルーティングを担う、現在唯一の標準的なEGPはどれか。", options: ["RIP", "OSPF", "BGP", "ICMP"], answer: 2, explain: "BGPは、組織間でのポリシー（通信経路の優先順位など）に基づいた経路選択を可能にするインターネットの基盤技術です。"},
    { id: 534, chapter: 5, text: "IGPにおいて、経路選択の基準（メトリック）として「経由するルータの数」のみを単純に考慮するプロトコルはどれか。", options: ["RIP", "OSPF", "BGP", "ICMP"], answer: 0, explain: "RIPはディスタンスベクタ型を採用しており、ホップ数（ルータの経由数）が少ないルートを最短とみなします。"},
    { id: 535, chapter: 5, text: "IP通信において、ネットワークのエラー通知や診断（pingなど）に使用される制御用プロトコルはどれか。", options: ["ICMP", "BGP", "RIP", "OSPF"], answer: 0, explain: "ICMPは、通信経路上のエラー通知や到達確認を行うために不可欠な制御用プロトコルです。"},
    { id: 536, chapter: 5, text: "経路情報を交換する際に、ルータ間の距離（ホップ数など）をベクトルとして伝搬するルーティング方式を何と呼ぶか。", options: ["リンクステート型", "ディスタンスベクタ型", "静的ルーティング", "ポリシー型"], answer: 1, explain: "ディスタンスベクタ型は、隣接ルータと経路情報を交換して蓄積する方式であり、RIPが代表例です。"},
    { id: 537, chapter: 5, text: "各ルータがネットワーク全体の地図を把握し、最短経路を計算するルーティング方式を何と呼ぶか。", options: ["ディスタンスベクタ型", "リンクステート型", "ホップベース型", "フィルタリング型"], answer: 1, explain: "リンクステート型は、ネットワーク全体の状態を全ルータで共有する方式であり、OSPFなどが該当します。"},
    { id: 538, chapter: 5, text: "OSPFが採用しているルーティング方式はどれか。", options: ["ディスタンスベクタ型", "リンクステート型", "ランダム型", "パケット交換型"], answer: 1, explain: "OSPFは、各ルータがリンク状態を広告し、ネットワーク全体のマップを構築して最短経路を計算します。"},

    // --- 第6章 モバイル端末ハードウェア (30問) ---
    { id: 601, chapter: 6, text: "スマートフォンが待ち受け時に電波の受信回路を一定時間ごとにオンとオフを繰り返して動作させる制御はどれか。", options: ["間欠受信", "ページング", "ドーマント", "プリザベーション"], answer: 0, explain: "間欠受信は、一定周期で受信回路を起動させることでバッテリー消耗を抑える技術です。" },
    { id: 602, chapter: 6, text: "待ち受け端末に向けてネットワークから送信される呼び出し信号はどれか。", options: ["ドーマント", "プリザベーション", "ページング", "送信電力制御"], answer: 2, explain: "ページングは、着信を端末に知らせるための信号です。" },
    { id: 603, chapter: 6, text: "端末の送信電力を必要最低限に調整する制御はどれか。", options: ["送信電力制御", "プリザベーション", "間欠受信", "ドーマント"], answer: 0, explain: "送信電力制御により、干渉の低減と電池消耗の抑制を図ります。" },
    { id: 604, chapter: 6, text: "パケット通信で回線を解放しつつIP接続状態を維持する待ち受け状態はどれか。", options: ["ページング", "プリザベーション", "間欠受信", "ドーマント"], answer: 3, explain: "ドーマント状態は無線チャネルを解放しつつ、通信再開を早める状態です。" },
    { id: 605, chapter: 6, text: "複雑な命令セットを持ち、パソコン向けCPUで主流のアーキテクチャはどれか。", options: ["CISC型", "RISC型", "A/D型", "D/A型"], answer: 0, explain: "CISCは複雑な命令を一つの命令で実行する方式です。" },
    { id: 606, chapter: 6, text: "命令を単純化し、スマホ向けに省電力化を実現したアーキテクチャはどれか。", options: ["CISC型", "RISC型", "CMOS型", "CCD型"], answer: 1, explain: "RISCは命令を簡素化して効率を高めたアーキテクチャです。" },
    { id: 607, chapter: 6, text: "無線の変復調や通信プロトコルを処理する通信専用プロセッサはどれか。", options: ["アプリケーションチップ", "ベースバンドチップ", "生体認証チップ", "RFIDチップ"], answer: 1, explain: "ベースバンドチップは通信に特化したプロセッサです。" },
    { id: 608, chapter: 6, text: "アプリ実行や画像処理など演算全般を担う頭脳チップはどれか。", options: ["ベースバンドチップ", "アプリケーションチップ", "データ通信モジュール", "パッシブモジュール"], answer: 1, explain: "アプリケーションチップ(AP)が端末の総合的な演算を担います。" },
    { id: 609, chapter: 6, text: "画素ごとのトランジスタで高速・高コントラストを実現する液晶方式はどれか。", options: ["TFT液晶", "TFD液晶", "有機ELディスプレイ", "パッシブ液晶"], answer: 0, explain: "TFT液晶は現在最も主流の駆動方式です。" },
    { id: 610, chapter: 6, text: "画素が自発光し、完全な黒が表現可能なディスプレイはどれか。", options: ["TFT液晶", "TFD液晶", "有機ELディスプレイ", "カラー液晶"], answer: 2, explain: "有機ELは自発光型のため、バックライトが不要で高コントラストです。" },
    { id: 611, chapter: 6, text: "電源を切るとデータが消える一時的な作業領域メモリはどれか。", options: ["ROM", "RAM", "SDカード", "USBメモリ"], answer: 1, explain: "RAMは動作中のデータの一時的な保管場所です。" },
    { id: 612, chapter: 6, text: "電源を切っても消えない不揮発性の記憶領域はどれか。", options: ["RAM", "キャッシュ", "レジスタ", "ROM"], answer: 3, explain: "ROM(フラッシュメモリ等)はデータの永続的な保存場所です。" },
    { id: 613, chapter: 6, text: "周波数とアンテナの長さの関係として正しいものはどれか。", options: ["高いほど短くなる", "高いほど長くなる", "一定である", "周波数に関係ない"], answer: 0, explain: "周波数が高くなると波長が短くなり、アンテナも短くなります。" },
    { id: 614, chapter: 6, text: "1.5GHzの電波で1/2波長アンテナとして最適な長さは何cmか。", options: ["5cm", "10cm", "15cm", "20cm"], answer: 1, explain: "1.5GHzの波長は約20cm、その1/2なので10cmです。" },
    { id: 615, chapter: 6, text: "2.0GHzの電波で1/2波長アンテナとして最適な長さは何cmか。", options: ["5.0cm", "7.5cm", "10.0cm", "12.5cm"], answer: 1, explain: "2.0GHzの波長は約15cm、その1/2なので7.5cmです。" },
    { id: 616, chapter: 6, text: "かつて使われた、メモリー効果が顕著な充電池はどれか。", options: ["リチウムイオン電池", "ニッケルカドミウム電池", "アルカリ乾電池", "鉛蓄電池"], answer: 1, explain: "ニカド電池はメモリー効果により容量が減りやすく注意が必要です。" },
    { id: 617, chapter: 6, text: "現在のスマホに採用され、メモリー効果がほぼ無い電池はどれか。", options: ["ニッケルカドミウム電池", "ニッケル水素電池", "リチウムイオン電池", "マンガン電池"], answer: 2, explain: "リチウムイオン電池は高性能でメモリー効果を気にせず充電できます。" },
    { id: 618, chapter: 6, text: "スマホカメラで主流の、高速読み出しと低消費電力なセンサーはどれか。", options: ["CCD", "CMOS", "LCD", "TFD"], answer: 1, explain: "CMOSセンサーは省電力で読み出しが速いのが特徴です。" },
    { id: 619, chapter: 6, text: "容量拡張に使われる、小型の外部記憶メディアはどれか。", options: ["SDカード", "USBメモリ", "ROM", "RAM"], answer: 0, explain: "microSDカードがモバイル機器の容量拡張によく使われます。" },
    { id: 620, chapter: 6, text: "PCなどで持ち運び可能なUSB接続のフラッシュメモリはどれか。", options: ["SDカード", "USBメモリ", "ベースバンドモジュール", "アプリケーションメディア"], answer: 1, explain: "USBメモリはPC等のデータ持ち運びの標準です。" },
    { id: 621, chapter: 6, text: "アナログ信号をデジタルデータに変換する処理はどれか。", options: ["A/D変換", "D/A変換", "変調", "復調"], answer: 0, explain: "Analog to Digital変換のことです。" },
    { id: 622, chapter: 6, text: "デジタルデータをアナログ信号に戻す処理はどれか。", options: ["A/D変換", "D/A変換", "符号化", "圧縮"], answer: 1, explain: "Digital to Analog変換のことです。" },
    { id: 623, chapter: 6, text: "指紋や顔などで本人確認を行う技術はどれか。", options: ["生体認証デバイス", "RFID", "パッシブタグ", "アクティブタグ"], answer: 0, explain: "バイオメトリクス（生体認証）によるセキュリティです。" },
    { id: 624, chapter: 6, text: "電波や電磁界で非接触でIDを読み書きする技術はどれか。", options: ["RFID", "A/D変換", "SIM", "USIM"], answer: 0, explain: "RFIDは非接触ID自動認識の総称です。" },
    { id: 625, chapter: 6, text: "電池を持たず、電波エネルギーで駆動する安価なRFIDタグはどれか。", options: ["アクティブタグ", "パッシブタグ", "デュアルSIM", "eSIM"], answer: 1, explain: "パッシブタグは電源不要で利用可能です。" },
    { id: 626, chapter: 6, text: "電池を内蔵し、遠距離通信が可能なRFIDタグはどれか。", options: ["パッシブタグ", "アクティブタグ", "USIM", "eSIM"], answer: 1, explain: "アクティブタグは能動的に電波を発信します。" },
    { id: 627, chapter: 6, text: "モバイル回線接続のための契約情報が記録された初代ICカードはどれか。", options: ["SIM", "USIM", "eSIM", "デュアルSIM"], answer: 0, explain: "SIMは契約者特定のためのモジュールカードです。" },
    { id: 628, chapter: 6, text: "SIMが拡張され、認証セキュリティが強化された3G以降の規格はどれか。", options: ["SIM", "USIM", "eSIM", "CTIA"], answer: 1, explain: "USIMは3G以降で標準化した高度なSIMです。" },
    { id: 629, chapter: 6, text: "2つの通信契約を1台で同時に待ち受けする機能はどれか。", options: ["eSIM", "デュアルSIM", "パッシブタグ", "アクティブタグ"], answer: 1, explain: "デュアルSIMで複数キャリアの運用が可能です。" },
    { id: 630, chapter: 6, text: "基板に組み込まれ、遠隔から契約情報を書き込めるSIMはどれか。", options: ["USIM", "eSIM", "アクティブタグ", "パッシブタグ"], answer: 1, explain: "eSIMは物理的なカード差し替え不要の組み込みSIMです。" },
    { id: 631, chapter: 6, text: "構造が単純で大容量化が容易だが、定期的なリフレッシュ動作が必要な主記憶メモリはどれか。", options: ["SRAM", "DRAM", "SSD", "キャッシュ"], answer: 1, explain: "DRAMはコンデンサに電荷を蓄える仕組みのため、定期的なリフレッシュが必要です。"},
    { id: 632, chapter: 6, text: "リフレッシュ動作が不要で非常に高速だが、構造が複雑で高価なメモリはどれか。", options: ["SRAM", "SDRAM", "DRAM", "SSD"],answer: 0, explain: "SRAMはフリップフロップ回路を使用するため、電源がある限り高速にデータ保持が可能で、CPUのキャッシュなどに使われます。"},
    { id: 633, chapter: 6, text: "メモリクロック信号に同期して動作し、高速なデータ転送を実現するメモリはどれか。", options: ["SRAM", "SDRAM", "DRAM", "ROM"], answer: 1, explain: "SDRAMはクロック信号とタイミングを合わせることで、データの転送効率を劇的に向上させたDRAMの一種です。"},
    { id: 634, chapter: 6, text: "記憶媒体にフラッシュメモリを使用し、HDDに比べて高速で耐衝撃性に優れた補助記憶装置はどれか。", options: ["DRAM", "SDRAM", "SRAM", "SSD"], answer: 3, explain: "SSDは機械的な駆動部を持たない半導体メモリ（フラッシュメモリ）による補助記憶装置です。"},
    { id: 635, chapter: 6, text: "プリンタの印字品質を表す単位で、1インチあたりのドット数を表すものはどれか。",options: ["dpi","bpi","dps","bps"], answer: 0, explain: "dpiはドット密度の単位で、印刷品質の指標となります。"},

    // --- 第7章 端末周辺技術 (30問) ---
    { id: 701, chapter: 7, text: "スマホをアクセスポイント代わりにして周辺機器をネットに繋ぐ機能はどれか。", options: ["ハンドオーバー", "テザリング", "ページング", "ローミング"], answer: 1, explain: "テザリングでPC等をネットへ接続できます。" },
    { id: 702, chapter: 7, text: "無線LAN規格の策定などを行う学会はどれか。", options: ["IETF", "IEEE", "GSMA", "ITU-T"], answer: 1, explain: "IEEEは無線LAN規格策定の主要な学会です。" },
    { id: 703, chapter: 7, text: "近距離無線通信技術Bluetoothが利用する周波数帯はどれか。", options: ["800MHz帯", "1.5GHz帯", "2.4GHz帯", "5GHz帯"], answer: 2, explain: "Bluetoothは免許不要の2.4GHz帯を使用します。" },
    { id: 704, chapter: 7, text: "Bluetoothで混信を避けるため周波数を高速切替する方式はどれか。", options: ["CDMA", "FHSS", "OFDM", "FDMA"], answer: 1, explain: "FHSSは周波数ホッピングにより干渉を回避します。" },
    { id: 705, chapter: 7, text: "かざすだけで通信する近距離無線通信の国際標準は何というか。", options: ["NFC", "LTE", "BLE", "HAPS"], answer: 0, explain: "NFCは非接触通信の国際標準規格です。" },
    { id: 706, chapter: 7, text: "交通系ICカード等で主流の、高速レスポンス非接触IC規格はどれか。", options: ["FeliCa", "Mifare", "QRコード", "Bluetooth"], answer: 0, explain: "FeliCaは高速処理が特徴のIC規格です。" },
    { id: 707, chapter: 7, text: "解像度の単位で、1インチあたりのドット数を示すものはどれか。", options: ["bps", "dpi", "Hz", "mAh"], answer: 1, explain: "dpiはドット密度（解像度）の単位です。" },
    { id: 708, chapter: 7, text: "紙の資料を読み取りデジタルデータにする入力機器はどれか。", options: ["プリンタ", "スキャナ", "プロジェクタ", "プロセッサ"], answer: 1, explain: "スキャナは画像読み取りのための入力装置です。" },
    { id: 709, chapter: 7, text: "1本の基幹ケーブルに機器を一列に接続する形態はどれか。", options: ["バス型", "スター型", "リング型", "メッシュ型"], answer: 0, explain: "バス型は単純ですが断線に弱い特徴があります。" },
    { id: 710, chapter: 7, text: "ハブに全機器を放射状に繋ぐ、現在のLAN主流形態はどれか。", options: ["バス型", "リング型", "スター型", "メッシュ型"], answer: 2, explain: "スター型は信頼性が高く現在の主流です。" },
    { id: 711, chapter: 7, text: "機器を円状に繋ぎ、データを一方向に巡回させる形態はどれか。", options: ["バス型", "スター型", "リング型", "アドホック型"], answer: 2, explain: "リング型はデータが一方向を回る構造です。" },
    { id: 712, chapter: 7, text: "横一方向の線の太さで数値を表すものはどれか。", options: ["バーコード", "QRコード", "FeliCa", "NFC"], answer: 0, explain: "バーコードは1次元コードです。" },
    { id: 713, chapter: 7, text: "格子状でバーコードの数百倍のデータを格納できるものはどれか。", options: ["バーコード", "QRコード", "RFID", "SIM"], answer: 1, explain: "QRコードは2次元コードで大容量です。" },
    { id: 714, chapter: 7, text: "有線LANの接続コネクタとして標準的な規格は何というか。", options: ["USB Type-C", "RJ-45", "HDMI", "D-Sub"], answer: 1, explain: "RJ-45はツイストペアケーブルのコネクタです。" },
    { id: 715, chapter: 7, text: "Bluetooth機器を初めて接続するための初期手続きを何というか。", options: ["テザリング", "ペアリング", "ハンドオーバー", "アタッチ"], answer: 1, explain: "ペアリングで安全な接続を確立します。" },
    { id: 716, chapter: 7, text: "FeliCaはNFC規格のどのタイプにあたるか。", options: ["Type A", "Type B", "Type F", "Type X"], answer: 2, explain: "NFC-FがFeliCaの規格タイプです。" },
    { id: 717, chapter: 7, text: "個人の身の回り機器を繋ぐ超近距離ネットワーク概念は何というか。", options: ["WAN", "LAN", "PAN", "MAN"], answer: 2, explain: "PANはPersonal Area Networkの略です。" },
    { id: 718, chapter: 7, text: "印刷データを一時的に保存して順番待ちさせる仕組みはどれか。", options: ["スプーリング", "ルーティング", "スケジューリング", "ペアリング"], answer: 0, explain: "スプーリングにより印刷処理を効率化します。" },
    { id: 719, chapter: 7, text: "スキャナの読み取り用半導体センサーはどれか。", options: ["CMOSイメージセンサー", "サーマルコントローラ", "Bluetoothモジュール", "パッシブタグ"], answer: 0, explain: "CMOSセンサーで紙面をデータ化します。" },
    { id: 720, chapter: 7, text: "一部の断線でも迂回して通信できる高信頼性な接続形態はどれか。", options: ["バス型", "スター型", "リング型", "メッシュ型"], answer: 3, explain: "メッシュ型は網の目のように接続されます。" },
    { id: 721, chapter: 7, text: "Bluetoothが干渉を避けるための周波数切り替えを何というか。", options: ["ホッピング", "ルーティング", "ハンドオーバー", "ブリッジ"], answer: 0, explain: "周波数ホッピングで干渉を防ぎます。" },
    { id: 722, chapter: 7, text: "NFCの読み取り距離は何センチ程度が標準か。", options: ["数メートル", "数十センチ", "数センチ", "数キロ"], answer: 2, explain: "NFCは数センチ以内の超近距離通信です。" },
    { id: 723, chapter: 7, text: "プリンタの接続に最も一般的に使われるインターフェースはどれか。", options: ["シリアル", "パラレル", "USB", "SCSI"], answer: 2, explain: "USBが現代の周辺機器接続の主流です。" },
    { id: 724, chapter: 7, text: "印刷データの単位で「1インチあたりのドット数」を何というか。", options: ["bps", "dpi", "Hz", "mAh"], answer: 1, explain: "dpiは解像度の指標です。" },
    { id: 725, chapter: 7, text: "PC等からプリンタへ無線LAN経由で印刷する仕組みを何というか。", options: ["有線接続", "無線LAN経由印刷", "赤外線印刷", "テザリング印刷"], answer: 1, explain: "ネットワーク上の共有プリンタとして無線印刷が可能です。" },
    { id: 726, chapter: 7, text: "バーコードの欠点は何か。", options: ["情報量が少ない", "製造が困難", "読み取り不能", "高価"], answer: 0, explain: "バーコードは記録できる情報量が少ないのが欠点です。" },
    { id: 727, chapter: 7, text: "QRコードが持つエラー復元機能の名称は何か。", options: ["誤り訂正", "暗号化", "データ圧縮", "テザリング"], answer: 0, explain: "汚れがあっても誤り訂正機能で読み取れます。" },
    { id: 728, chapter: 7, text: "Bluetoothの通信ペアリングの主な目的は何か。", options: ["充電", "安全な鍵交換と認証", "画面共有", "通信距離の延長"], answer: 1, explain: "ペアリングで信頼関係を確立します。" },
    { id: 729, chapter: 7, text: "メッシュ型の最大の特徴は何か。", options: ["低コスト", "高信頼性と冗長性", "単純な配線", "低消費電力"], answer: 1, explain: "メッシュ型はルートが複数あるため高信頼です。" },
    { id: 730, chapter: 7, text: "Bluetoothが利用するISMバンドの周波数帯は？", options: ["1GHz帯", "2.4GHz帯", "5GHz帯", "10GHz帯"], answer: 1, explain: "2.4GHz帯を利用する免許不要の周波数帯です。" },
    { id: 731, chapter: 7, text: "IEEE 802.11規格において、現在「Wi-Fi 6」と呼ばれている無線LAN規格はどれか。", options: ["IEEE 802.11ac", "IEEE 802.11ax", "IEEE 802.11be", "IEEE 802.11n"], answer: 1, explain: "IEEE 802.11axは、混雑した環境での通信効率を改善した規格で、Wi-Fi 6として知られています。"},
    { id: 732, chapter: 7, text: "IEEE 802.11規格において、現在「Wi-Fi 7」として位置付けられている最新の規格はどれか。", options: ["IEEE 802.11ax", "IEEE 802.11ac", "IEEE 802.11be", "IEEE 802.11n"], answer: 2, explain: "IEEE 802.11beは、非常に高いスループットと低遅延を実現する次世代の無線LAN規格です。"},
    { id: 733, chapter: 7, text: "IEEE 802.16規格の無線技術が、その移動可能な仕様として普及させたブランド名称は何か。", options: ["Wi-Fi", "WiMAX", "Bluetooth", "ZigBee"], answer: 1, explain: "IEEE 802.16はWiMAXの技術的基礎となった規格であり、広域無線アクセスをターゲットにしていました。"},
    { id: 734, chapter: 7, text: "IEEE 802.11とIEEE 802.16の適用範囲の違いとして、最も適切なものはどれか。", options: ["802.11は広域（MAN）、802.16は短距離（LAN）である", "802.11は短距離（LAN）、802.16は広域（MAN）を想定している", "両方とも短距離（LAN）専用である", "両方とも全世界をカバーする広域用である"], answer: 1, explain: "802.11は数十メートルのLAN向け、802.16は数キロメートルをカバーする広域ネットワーク（MAN）向けです。"},
    { id: 735, chapter: 7, text: "NFCが使用する周波数帯として、正しいものはどれか。", options: ["2.4GHz帯", "13.56MHz帯", "920MHz帯", "5GHz帯"], answer: 1, explain: "NFCは国際標準規格として13.56MHz帯を使用する近距離無線通信です。"},
    { id: 736, chapter: 7, text: "NFCの特徴として、適切なものはどれか。", options: ["数キロメートル先まで通信できる", "通信距離が数センチ程度と非常に短い", "Bluetoothの別名である", "衛星を使用した通信である"], answer: 1, explain: "NFCは数センチメートル程度の範囲で通信を行うため、意図しない通信を防ぎ高い利便性とセキュリティを両立しています。"},
    { id: 737, chapter: 7, text: "日本のデンソーが開発したQRコードのデータ量として適切なものはどれか。", options: ["数字、英数字ともに7,000文字", "数字で5,000文字、英数字で4,000文字", "数字で7,000文字、英数字で4,000文字", "数字で4,000文字、英数字で3,000文字"], answer: 2, explain: "数字で約7,000文字、英数字で約4,000文字、漢字では約2,000文字のデータを格納できます。"},

    // --- 第8章 モバイル端末のソフトウェア技術 (30問) ---
    { id: 801, chapter: 8, text: "モバイル端末のハードウェア管理とアプリの実行基盤となるのは何か。", options: ["アプリ", "ミドルウェア", "OS", "API"], answer: 2, explain: "OSは基本ソフトウェアであり、端末の基盤です。" },
    { id: 802, chapter: 8, text: "OSとアプリの間に位置し、共通処理を提供するものは何か。", options: ["アプリ", "ミドルウェア", "ハードウェア", "CPU"], answer: 1, explain: "ミドルウェアはOSの機能を拡張し、アプリに共通処理を提供します。" },
    { id: 803, chapter: 8, text: "アプリがOS機能を利用するための窓口となる仕様はどれか。", options: ["SDK", "コンテナ", "API", "CPU"], answer: 2, explain: "APIが機能利用のための窓口です。" },
    { id: 804, chapter: 8, text: "アプリがハードウェア処理をOSに要求する命令は何か。", options: ["システムコール", "コンパイル", "コーデック", "タスク"], answer: 0, explain: "システムコールによりOSへ処理を要求します。" },
    { id: 805, chapter: 8, text: "OSがCPU割り当てやメモリ管理を行う対象は何か。", options: ["API", "CPUと主記憶装置", "コンパイラ", "タスク"], answer: 1, explain: "OSはCPUと主記憶装置（メモリ）を効率的に管理します。" },
    { id: 806, chapter: 8, text: "アプリ開発に必要なツール等をまとめた開発キットはどれか。", options: ["API", "SDK", "システムコール", "タスク"], answer: 1, explain: "SDKは開発に必要なツール群です。" },
    { id: 807, chapter: 8, text: "ソースコードを実行形式に変換するソフトはどれか。", options: ["コンパイラ", "エンコーダ", "デコーダ", "タスク"], answer: 0, explain: "コンパイラはコードを機械語へ変換します。" },
    { id: 808, chapter: 8, text: "メモリ空間を持ち独立して動くプログラム実行単位はどれか。", options: ["スレッド", "タスク", "コーデック", "CPU"], answer: 1, explain: "タスク（プロセス）は独立した実行単位です。" },
    { id: 809, chapter: 8, text: "タスク内の並行処理を行う最小単位はどれか。", options: ["スレッド", "タスク", "コンテナ", "API"], answer: 0, explain: "スレッドはタスク内の最小処理単位です。" },
    { id: 810, chapter: 8, text: "Windowsでのアプリ共通プラットフォーム規格は何か。", options: ["UWP", "ACPI", "SDK", "OTA"], answer: 0, explain: "UWPが共通アプリ規格です。" },
    { id: 811, chapter: 8, text: "OSがハードウェアの電力消費を一元管理する規格は何か。", options: ["API", "ACPI", "SDK", "FOTA"], answer: 1, explain: "ACPIが電力制御の標準規格です。" },
    { id: 812, chapter: 8, text: "フィーチャーフォンOSの最大の特徴は何か。", options: ["汎用性", "専用最適化・省電力", "メモリ大容量", "アプリ追加自由"], answer: 1, explain: "専用OSで省電力と安定性を重視していました。" },
    { id: 813, chapter: 8, text: "スマホOSが進化してきた方向性は何か。", options: ["専用最適化", "汎用化・共通プラットフォーム化", "回線交換専用", "電力無視"], answer: 1, explain: "スマホOSは汎用的な基盤へと進化しました。" },
    { id: 814, chapter: 8, text: "サイズを小さくする処理は何か。", options: ["データ圧縮", "システムコール", "デコード", "コンパイル"], answer: 0, explain: "データ圧縮により通信や容量を節約します。" },
    { id: 815, chapter: 8, text: "データを符号化し圧縮・暗号化する処理はどれか。", options: ["エンコード", "デコード", "タスク", "スレッド"], answer: 0, explain: "エンコードは符号化・圧縮処理です。" },
    { id: 816, chapter: 8, text: "圧縮データを元に戻す処理はどれか。", options: ["エンコード", "デコード", "コンテナ", "API"], answer: 1, explain: "デコードは復元処理です。" },
    { id: 817, chapter: 8, text: "音声動画の圧縮/伸張技術やソフトの総称はどれか。", options: ["コーデック", "コンテナ", "CPU", "SDK"], answer: 0, explain: "コーデックが圧縮伸張の技術です。" },
    { id: 818, chapter: 8, text: "携帯音声通話向けの音声圧縮規格は何か。", options: ["AMR", "MP3", "AAC", "JPEG"], answer: 0, explain: "AMRが音声通話で使われる規格です。" },
    { id: 819, chapter: 8, text: "音楽再生で広く使われる非可逆の音声規格は何か。", options: ["MP3", "GIF", "PNG", "ZIP"], answer: 0, explain: "MP3は音楽圧縮の代表規格です。" },
    { id: 820, chapter: 8, text: "MP3より後発で高音質な音楽コーデックは何か。", options: ["WMA", "AAC", "AMR", "JPEG"], answer: 1, explain: "AACはMP3より高効率な規格です。" },
    { id: 821, chapter: 8, text: "写真の保存で主流の非可逆圧縮画像は何というか。", options: ["GIF", "PNG", "JPEG", "ZIP"], answer: 2, explain: "JPEGが写真保存の主流です。" },
    { id: 822, chapter: 8, text: "透過やアニメ対応でWebで使われる画像規格は何というか。", options: ["JPEG XR", "HEIF", "GIF", "MP3"], answer: 2, explain: "GIFは透過・アニメ対応の規格です。" },
    { id: 823, chapter: 8, text: "劣化なしの可逆圧縮でWeb用に使われる規格は何か。", options: ["JPEG", "PNG", "GIF", "WMA"], answer: 1, explain: "PNGは劣化なしの可逆画像規格です。" },
    { id: 824, chapter: 8, text: "5G時代の新しい静止画規格で高効率なものは何か。", options: ["HEIF", "AMR", "TGZ", "ACPI"], answer: 0, explain: "HEIFは高圧縮な最新画像規格です。" },
    { id: 825, chapter: 8, text: "動画の滑らかさ（1秒のコマ数）は何というか。", options: ["dpi", "フレームレート", "コーデック", "コンテナ"], answer: 1, explain: "フレームレートが滑らかさの指標です。" },
    { id: 826, chapter: 8, text: "映像と音声を1ファイルに包む形式は何か。", options: ["コーデック", "システムコール", "コンテナフォーマット", "ミドルウェア"], answer: 2, explain: "コンテナフォーマットが包む役割をします。" },
    { id: 827, chapter: 8, text: "複数のファイルを可逆圧縮してまとめる汎用規格は何か。", options: ["JPEG", "MP3", "ZIP", "AMR"], answer: 2, explain: "ZIPはファイルまとめと圧縮の標準です。" },
    { id: 828, chapter: 8, text: "Linux等で使われるtarとgzipを組み合わせた形式は何か。", options: [".zip", ".tgw", ".tgz", ".exe"], answer: 2, explain: ".tgzはtarとgzipを併用した形式です。" },
    { id: 829, chapter: 8, text: "無線経由でソフト更新を行う技術は何か。", options: ["ACPI", "UWP", "OTA", "CISC"], answer: 2, explain: "OTAが無線更新技術の総称です。" },
    { id: 830, chapter: 8, text: "ファームウェア（OS）を無線更新する仕組みはどれか。", options: ["FOTA", "FDD", "FHSS", "FMC"], answer: 0, explain: "FOTAがファームウェアの無線更新です。" },
    { id: 831, chapter: 8, text: "モバイル端末のOSについて、最も適切な記述はどれか。", options: ["OSはアプリケーションの一部として動作する", "OSはハードウェア資源を管理する基本ソフトウェアである", "OSはネットワーク機能のみを提供する", "OSはユーザインターフェイスを持たない"], answer: 1, explain: "OSは、CPU、メモリ、ストレージ、無線通信チップなどのハードウェアを効率的に管理し、アプリケーションがそれらを直接操作せずに済むように仲介しています。" },
    { id: 832, chapter: 6, text: "フラッシュメモリの性質として、正しいものはどれか。", options: ["電源を切るとデータが消える", "機械的な駆動部がある", "不揮発性である", "リフレッシュ動作が必要"], answer: 2, explain: "フラッシュメモリは不揮発性メモリであり、電源オフでもデータを保持できます。"},
    { id: 833, chapter: 6, text: "フラッシュメモリの書き込みにおける特性として、適切なものはどれか。", options: ["ブロック単位で消去してから書き込む必要がある", "常に1バイト単位で自由に書き換え可能", "書き込みは読み出しより必ず高速である", "書き換え寿命は無限である"], answer: 0, explain: "フラッシュメモリ（NAND型など）は、書き込み前に一度ブロック単位での消去処理が必要な特性があります。"},
    { id: 834, chapter: 6, text: "HDDと比較した際のSSDの利点として、不適切なものはどれか。", options: ["読み込みが非常に早い", "機械的駆動部がなく耐衝撃性に優れる", "容量単価が安い", "小型で軽量"], answer: 2, explain: "SSDはHDDに比べ、容量当たりの単価が高い（コスパが悪い）ことが特徴です。"},

    // --- 第9章 モバイル端末のソフトウェア技術2 (30問) ---
    { id: 901, chapter: 9, text: "電波経由でインターネットにアクセスする通信形態はどれか。", options: ["モバイルインターネット接続", "固定ブロードバンド接続", "スタンドアロン接続", "分散接続"], answer: 0, explain: "モバイル網を利用する接続形態です。" },
    { id: 902, chapter: 9, text: "スマホをアクセスポイント代わりにする機能は何か。", options: ["ハンドオーバー", "ページング", "テザリング", "ローミング"], answer: 2, explain: "テザリングで周辺機器をネットに繋げます。" },
    { id: 903, chapter: 9, text: "テザリングでIPを透過的に中継する方式はどれか。", options: ["ルータタイプ", "ブリッジタイプ", "ブロードバンドタイプ", "スタンドアロンタイプ"], answer: 1, explain: "ブリッジタイプはスマホが透過中継します。" },
    { id: 904, chapter: 9, text: "テザリングでスマホがIPを払い出し仲介する方式はどれか。", options: ["ブリッジタイプ", "ルータタイプ", "ブロードバンドタイプ", "分散タイプ"], answer: 1, explain: "ルータタイプが現在の主流方式です。" },
    { id: 905, chapter: 9, text: "文書同士をリンクで結びつけ参照できるテキスト構造はどれか。", options: ["ハイパーテキスト", "マークアップ", "ネイティブコード", "ソースコード"], answer: 0, explain: "ハイパーテキストがWWWの基盤です。" },
    { id: 906, chapter: 9, text: "文章構造をタグで指定する言語はどれか。", options: ["JavaScript", "CSS", "HTML", "HTTP"], answer: 2, explain: "HTMLが文書構造指定のマークアップ言語です。" },
    { id: 907, chapter: 9, text: "Webブラウザとサーバー間の送受信プロトコルはどれか。", options: ["HTML", "HTTP", "TCP", "IP"], answer: 1, explain: "HTTPがWeb通信用プロトコルです。" },
    { id: 908, chapter: 9, text: "ブラウザを高度なアプリ実行基盤にした標準仕様は何というか。", options: ["HTML5", "HTTP/2", "OMA", "DRM"], answer: 0, explain: "HTML5でリッチなWebアプリが動きます。" },
    { id: 909, chapter: 9, text: "Webページに動きをつける標準言語は何か。", options: ["HTML", "CSS", "JavaScript", "コンパイラ"], answer: 2, explain: "JavaScriptが動的機能の言語です。" },
    { id: 910, chapter: 9, text: "ページの色や配置など見た目を指定する仕様は何か。", options: ["JavaScript", "CSS", "HTTP", "コンテナ"], answer: 1, explain: "CSSがデザイン指定の仕様です。" },
    { id: 911, chapter: 9, text: "ネット経由でITリソースを利用する形態は何か。", options: ["クラウドコンピューティング", "スタンドアロン", "プリインストール", "著作権管理"], answer: 0, explain: "クラウドがネット経由の計算資源提供です。" },
    { id: 912, chapter: 9, text: "クラウドの標準モデルを策定した米国政府機関は何か。", options: ["IETF", "IEEE", "NIST", "OMA"], answer: 2, explain: "NISTがクラウド定義を策定しました。" },
    { id: 913, chapter: 9, text: "サーバーを分散させ協調動作させる仕組みは何か。", options: ["スタンドアロン", "分散コンピューティング", "ネイティブアプリ", "ポストインストール"], answer: 1, explain: "分散コンピューティングが協調処理を担います。" },
    { id: 914, chapter: 9, text: "完成されたアプリをネット経由で利用するクラウド形態は何か。", options: ["IaaS", "PaaS", "SaaS", "Web3"], answer: 2, explain: "SaaSが完成品アプリの利用形態です。" },
    { id: 915, chapter: 9, text: "アプリ実行の環境を提供し開発を支援するクラウドはどれか。", options: ["SaaS", "PaaS", "IaaS", "NFT"], answer: 1, explain: "PaaSはプラットフォーム提供型です。" },
    { id: 916, chapter: 9, text: "インフラ資源（仮想サーバー等）を提供するクラウドはどれか。", options: ["SaaS", "PaaS", "IaaS", "CDD"], answer: 2, explain: "IaaSはインフラストラクチャ提供型です。" },
    { id: 917, chapter: 9, text: "端末にインストールして直接CPUで動くアプリは何というか。", options: ["Webアプリ", "ネイティブアプリ", "クラウドアプリ", "分散アプリ"], answer: 1, explain: "ネイティブアプリがOS上で直接動きます。" },
    { id: 918, chapter: 9, text: "最初から組み込まれ削除不可なアプリを何というか。", options: ["プリインストール", "ポストインストール", "ダウンロード", "ファームウェア"], answer: 0, explain: "プリインストールが工場出荷時のアプリです。" },
    { id: 919, chapter: 9, text: "購入後にユーザーが追加するアプリは何か。", options: ["プリインストール", "ポストインストール", "システムインストール", "ファームウェア"], answer: 1, explain: "ポストインストールが後入れアプリです。" },
    { id: 920, chapter: 9, text: "著作権を厳格に保護・管理する技術は何というか。", options: ["SDK", "CDD", "DRM", "CTS"], answer: 2, explain: "DRMがコンテンツ保護技術です。" },
    { id: 921, chapter: 9, text: "モバイル技術標準化を推進する業界団体は何か。", options: ["NIST", "OMA", "IEEE", "IETF"], answer: 1, explain: "OMAがモバイル標準化団体です。" },
    { id: 922, chapter: 9, text: "転送禁止のみ行う単純なDRM配信方式はどれか。", options: ["Forward Lock", "Combined Delivery", "Separate Delivery", "NFT"], answer: 0, explain: "Forward Lockは転送を防ぎます。" },
    { id: 923, chapter: 9, text: "コンテンツと鍵を別々に配信するDRM方式はどれか。", options: ["Forward Lock", "Combined Delivery", "Separate Delivery", "CDD"], answer: 2, explain: "Separate Deliveryは個別配信です。" },
    { id: 924, chapter: 9, text: "Androidの互換性基準を定めた文書はどれか。", options: ["CTS", "CDD", "DRM", "SDK"], answer: 1, explain: "CDDが互換性の定義文書です。" },
    { id: 925, chapter: 9, text: "Android互換性の自動検証テストプログラムはどれか。", options: ["CDD", "CTS", "SDK", "OMA"], answer: 1, explain: "CTSで互換性を自動テストします。" },
    { id: 926, chapter: 9, text: "仮想空間に入る技術は何というか。", options: ["AR", "VR", "MR", "スタンドアロン"], answer: 1, explain: "VRが仮想空間への没入技術です。" },
    { id: 927, chapter: 9, text: "現実にバーチャル情報を重ねる技術は何というか。", options: ["VR", "AR", "MR", "スタンドアロン"], answer: 1, explain: "ARが現実への情報付加技術です。" },
    { id: 928, chapter: 9, text: "改ざん不可能にする分散型台帳技術は何か。", options: ["クラウド", "ブロックチェーン", "ネイティブアプリ", "システムコール"], answer: 1, explain: "ブロックチェーンが改ざん不可能にする台帳です。" },
    { id: 929, chapter: 9, text: "唯一無二であることを証明するデジタル資産は何というか。", options: ["NFT", "SaaS", "CTS", "OMA"], answer: 0, explain: "NFTが資産の唯一性証明に使われます。" },
    { id: 930, chapter: 9, text: "分散型技術による次世代インターネット概念は何か。", options: ["Web2.0", "Web3", "モバイルクラウド", "メタバース"], answer: 1, explain: "Web3が次世代の分散型ネットです。" },

    // --- 第10章 生成AIとAI活用 (30問) ---
    { id: 1001, chapter: 10, text: "デジタル技術でビジネスモデルを変革することを何と呼ぶか。", options: ["DX", "IoT", "UI", "API"], answer: 0, explain: "DX(デジタルトランスフォーメーション)です。" },
    { id: 1002, chapter: 10, text: "コンピュータに知的な振る舞いを再現させた技術の総称は何か。", options: ["IoT", "AI", "トークン", "プロンプト"], answer: 1, explain: "AI(人工知能)です。" },
    { id: 1003, chapter: 10, text: "データからコンピュータ自身に規則性を学習させる技術は何か。", options: ["統計解析", "機械学習", "チャットUI", "外部知識"], answer: 1, explain: "機械学習がデータから学習する技術です。" },
    { id: 1004, chapter: 10, text: "入力データと正解ラベルで学習する手法はどれか。", options: ["教師あり学習", "教師無し学習", "強化学習", "ファインチューニング"], answer: 0, explain: "教師あり学習はラベル付けされたデータを使います。" },
    { id: 1005, chapter: 10, text: "正解ラベルを使わずデータから構造を発見する手法はどれか。", options: ["教師あり学習", "教師無し学習", "強化学習", "外部知識"], answer: 1, explain: "教師無し学習は構造を自動発見します。" },
    { id: 1006, chapter: 10, text: "報酬を最大化するよう行動を学ばせる手法はどれか。", options: ["教師あり学習", "教師無し学習", "強化学習", "ファインチューニング"], answer: 2, explain: "強化学習は報酬最大化を目指します。" },
    { id: 1007, chapter: 10, text: "脳の神経回路を模した情報処理システムはどれか。", options: ["ニューラルネットワーク", "統計解析", "プロンプト", "コンテナ"], answer: 0, explain: "ニューラルネットワークが脳を模した構造です。" },
    { id: 1008, chapter: 10, text: "多層構造で特徴を自律的に抽出・学習する技術はどれか。", options: ["統計解析", "ディープラーニング", "ファインチューニング", "チャットUI"], answer: 1, explain: "ディープラーニングが深層学習です。" },
    { id: 1009, chapter: 10, text: "新しいコンテンツを作り出すAI技術は何か。", options: ["生成AI", "統計解析", "外部知識", "IoT"], answer: 0, explain: "生成AIがコンテンツを作り出します。" },
    { id: 1010, chapter: 10, text: "膨大なテキストで学習した大規模言語モデルの略称はどれか。", options: ["LLM", "IoT", "ACPI", "SDK"], answer: 0, explain: "LLM(大規模言語モデル)です。" },
    { id: 1011, chapter: 10, text: "AIへの指示文を何というか。", options: ["トークン", "プロンプト", "システムコール", "コーデック"], answer: 1, explain: "プロンプトで指示を与えます。" },
    { id: 1012, chapter: 10, text: "LLMの処理最小単位や料金基準となるのは何か。", options: ["プロンプト", "トークン", "バッファ", "セグメント"], answer: 1, explain: "トークンが処理の単位です。" },
    { id: 1013, chapter: 10, text: "特定用途に特化してモデルを微調整する手法はどれか。", options: ["統計解析", "ファインチューニング", "強化学習", "デコード"], answer: 1, explain: "ファインチューニングで微調整します。" },
    { id: 1014, chapter: 10, text: "文字以外の情報を同時に処理できるAIの性質はどれか。", options: ["推論型LLM", "マルチモーダル", "外部知識", "チャットUI"], answer: 1, explain: "マルチモーダルは複数媒体を処理可能です。" },
    { id: 1015, chapter: 10, text: "論理的な思考ステップを実行してから回答するLLMは何型か。", options: ["マルチモーダルLLM", "推論型LLM", "統計解析AI", "外部知識AI"], answer: 1, explain: "推論型LLMは思考プロセスを実行します。" },
    { id: 1016, chapter: 10, text: "生成AIと検索エンジンの違いは何か。", options: ["AIはコピペしかしない", "AIはその場で回答を創出する", "検索エンジンはテキスト不可", "AIは画像不可"], answer: 1, explain: "AIはその場で回答を組み立て(創出)ます。" },
    { id: 1017, chapter: 10, text: "対話形式でAIを利用できる画面設計を何というか。", options: ["API", "チャットUI", "外部知識", "SDK"], answer: 1, explain: "チャットUIで対話します。" },
    { id: 1018, chapter: 10, text: "回答生成時に外部データを一時的に参照させる仕組みは何の背景か。", options: ["外部知識の活用", "ファインチューニング", "強化学習", "アタッチ制御"], answer: 0, explain: "外部知識の活用（RAG等）です。" },
    { id: 1019, chapter: 10, text: "自社システムで外部AI機能を使うための接続点は何か。", options: ["UI", "API", "コンテナ", "HSS"], answer: 1, explain: "APIでシステム連携します。" },
    { id: 1020, chapter: 10, text: "学習データに偏りがある場合に発生する問題は何か。", options: ["プライバシー侵害", "バイアス", "ハルシネーション", "ガイドライン"], answer: 1, explain: "バイアスが偏りを生みます。" },
    { id: 1021, chapter: 10, text: "プロンプトに入力した機密データが他者に流用されるリスクを防ぐための対策は何か。", options: ["画面を消す", "再学習除外設定(オプトアウト)や企業向け契約を利用する", "メモリを増やす", "テザリングを切る"], answer: 1, explain: "再学習除外設定で漏洩を防ぎます。" },
    { id: 1022, chapter: 10, text: "利用ルールを取りまとめた文書は何か。", options: ["SDK", "利用ガイドライン", "ファインチューニング仕様書", "ネットワークスライシング"], answer: 1, explain: "利用ガイドラインでルールを決めます。" },
    { id: 1023, chapter: 10, text: "AIの判断理由を説明可能にする原則はどれか。", options: ["プライバシーの保護", "説明責任と透明性", "データのバイアス", "コンテキストウィンドウ"], answer: 1, explain: "説明責任と透明性が重要です。" },
    { id: 1024, chapter: 10, text: "モデルの賢さを表す結合の強さの指標はどれか。", options: ["パラメータ", "トークン", "プロンプト", "ゲートウェイ"], answer: 0, explain: "パラメータがモデルの規模を示します。" },
    { id: 1025, chapter: 10, text: "生成AI活用で不適切な行為はどれか。", options: ["要約させる", "著作権コンテンツの無断再販売", "技術論文の翻訳", "バグ修正"], answer: 1, explain: "著作権侵害は重大なトラブルです。" },
    { id: 1026, chapter: 10, text: "AIが自信満々に嘘をつく現象を何というか。", options: ["バイアス", "ハルシネーション", "プロンプト", "ドーマント"], answer: 1, explain: "ハルシネーション(幻覚)です。" },
    { id: 1027, chapter: 10, text: "データ収集と分析をセットにした全体像はどれか。", options: ["FMCとMIMO", "IoTとAI", "MNPとeSIM", "4Gと回線交換"], answer: 1, explain: "IoTとAIがセットで機能します。" },
    { id: 1028, chapter: 10, text: "思考を順に追わせる手法を何というか。", options: ["思考の連鎖", "ファインチューニング", "強化学習", "パワーコントロール"], answer: 0, explain: "思考の連鎖(CoT)で正答率が上がります。" },
    { id: 1029, chapter: 10, text: "再学習利用を拒否する契約上の申請は何というか。", options: ["オプトイン", "オプトアウト", "ページング", "スプーリング"], answer: 1, explain: "オプトアウトで再学習を防ぎます。" },
    { id: 1030, chapter: 10, text: "AI時代のデジタル人材に求められる姿勢はどれか。", options: ["すべて盲信", "特性を理解し監督の上で使いこなす", "一切使わない", "個人情報を詰め込む"], answer: 1, explain: "正しく理解し使いこなすことが必要です。" },

    // --- 第11章 情報セキュリティ管理 (30問) ---
    { id: 1101, chapter: 11, text: "攻撃者が狙える侵入口が増えている現代の課題は何というか。", options: ["シングルサインオンの拡大", "アタックサーフェイスの拡大", "境界防御の拡大", "ベースラインの拡大"], answer: 1, explain: "アタックサーフェイスが攻撃対象領域です。" },
    { id: 1102, chapter: 11, text: "フリーWi-Fi利用時の最大のリスクは何か。", options: ["バッテリー発火", "通信傍受", "OS初期化", "GPS偽装"], answer: 1, explain: "暗号化なしのWi-Fiは通信傍受のリスクがあります。" },
    { id: 1103, chapter: 11, text: "正規ユーザーのみがアクセス可能にする特性は何か。", options: ["可用性", "完全性", "機密性", "真正性"], answer: 2, explain: "機密性は情報漏洩を防ぎます。" },
    { id: 1104, chapter: 11, text: "データが正確で改ざんされていない特性は何か。", options: ["機密性", "完全性", "可用性", "責任追跡性"], answer: 1, explain: "完全性はデータの正確さを保証します。" },
    { id: 1105, chapter: 11, text: "必要なときにいつでもアクセスできる状態は何か。", options: ["機密性", "信頼性", "完全性", "可用性"], answer: 3, explain: "可用性はシステムの停止を防ぎます。" },
    { id: 1106, chapter: 11, text: "悪意あるソフトの総称は何か。", options: ["マルウェア", "ファイアウォール", "クッキー", "スプーリング"], answer: 0, explain: "マルウェアが悪意あるソフトです。" },
    { id: 1107, chapter: 11, text: "標準的な基準を自組織と照らすリスク分析はどれか。", options: ["詳細リスク分析", "非形式的アプローチ", "ベースラインアプローチ", "組み合わせアプローチ"], answer: 2, explain: "ベースラインが基準照合です。" },
    { id: 1108, chapter: 11, text: "専門家の経験で定性的に判断するリスク分析はどれか。", options: ["ベースラインアプローチ", "詳細リスク分析", "組み合わせアプローチ", "非形式的アプローチ"], answer: 3, explain: "非形式的アプローチは専門家の知見を用います。" },
    { id: 1109, chapter: 11, text: "全資産を数値化し厳密に算出するリスク分析はどれか。", options: ["詳細リスク分析", "ベースラインアプローチ", "非形式的アプローチ", "組み合わせアプローチ"], answer: 0, explain: "詳細リスク分析は厳密に評価します。" },
    { id: 1110, chapter: 11, text: "複数のリスク分析手法を併用するアプローチはどれか。", options: ["ゼロトラスト", "非形式的アプローチ", "組み合わせアプローチ", "多要素アプローチ"], answer: 2, explain: "組み合わせアプローチが効率的です。" },
    { id: 1111, chapter: 11, text: "端末持ち出し時の不適切な対策はどれか。", options: ["常に肌身離さず管理", "パスワード設定", "VPNなしでの自動接続", "プライバシーフィルター"], answer: 2, explain: "VPNなしの自動接続は危険です。" },
    { id: 1112, chapter: 11, text: "紛失時の初動対応はどれか。", options: ["放置する", "SNSで公開する", "管理者に即連絡し遠隔ロック", "自分で買う"], answer: 2, explain: "即時の報告とリモート対応が鉄則です。" },
    { id: 1113, chapter: 11, text: "SMSで偽サイトへ誘導する詐欺手口は何か。", options: ["スミッシング", "スプーフィング", "ランサムウェア", "ハッシュ化"], answer: 0, explain: "スミッシングがSMSフィッシングです。" },
    { id: 1114, chapter: 11, text: "スマホ等を統合管理する仕組みはどれか。", options: ["SIEM", "EMM", "SBOM", "PKI"], answer: 1, explain: "EMMが統合管理システムです。" },
    { id: 1115, chapter: 11, text: "あらゆるデバイスを統合管理する進化した仕組みはどれか。", options: ["EMM", "SIEM", "UEM", "SOC"], answer: 2, explain: "UEMが統合エンドポイント管理です。" },
    { id: 1116, chapter: 11, text: "WPA3でPSKの弱点を克服する鍵交換規格はどれか。", options: ["SAE", "TKIP", "CCMP", "IPSec"], answer: 0, explain: "SAEが安全な鍵交換をします。" },
    { id: 1117, chapter: 11, text: "認証サーバによる強固なアクセス制御はどれか。", options: ["PSK", "IEEE 802.1x", "L2TP", "SBOM"], answer: 1, explain: "IEEE 802.1xが認証サーバを使います。" },
    { id: 1118, chapter: 11, text: "WPA2等で使うAES暗号の方式はどれか。", options: ["SAE", "TKIP", "CCMP", "CNSA Suite"], answer: 2, explain: "CCMPがAES暗号化方式です。" },
    { id: 1119, chapter: 11, text: "Webブラウザで手軽にVPN接続する方式はどれか。", options: ["IPSec", "L2TP", "SSL-VPN", "EMM"], answer: 2, explain: "SSL-VPNがブラウザ利用に便利です。" },
    { id: 1120, chapter: 11, text: "攻撃ログを一元管理し予兆を分析するシステムは何か。", options: ["SOC", "SIEM", "SBOM", "PKI"], answer: 1, explain: "SIEMがログ分析システムです。" },
    { id: 1121, chapter: 11, text: "ソフトウェアの部品表を何というか。", options: ["SBOM", "SIEM", "EMM", "UEM"], answer: 0, explain: "SBOMがソフトウェア構成表です。" },
    { id: 1122, chapter: 11, text: "DL実行しデータを残さない方式はどれか。", options: ["画面転送型", "ネットブート型", "ファット型", "スタンドアロン型"], answer: 1, explain: "ネットブート型がデータ非保持方式です。" },
    { id: 1123, chapter: 11, text: "復号に同じ鍵を使う暗号方式はどれか。", options: ["共通鍵暗号方式", "公開鍵暗号方式", "ハイブリッド方式", "ハッシュ化"], answer: 0, explain: "共通鍵方式が同一鍵を使います。" },
    { id: 1124, chapter: 11, text: "公開鍵と秘密鍵を使う方式はどれか。", options: ["共通鍵暗号方式", "ハッシュ化", "公開鍵暗号方式", "デジタル署名"], answer: 2, explain: "公開鍵方式がペア鍵を使います。" },
    { id: 1125, chapter: 11, text: "不可逆な文字列を生成するアルゴリズムは何か。", options: ["ハイブリッド方式", "共通鍵暗号方式", "デジタル署名", "ハッシュ化"], answer: 3, explain: "ハッシュ化は改ざん検知に使います。" },
    { id: 1126, chapter: 11, text: "本人の作成を証明する仕組みはどれか。", options: ["ゼロトラスト", "シングルサインオン", "デジタル署名", "リスクベース認証"], answer: 2, explain: "デジタル署名が真正性を証明します。" },
    { id: 1127, chapter: 11, text: "公開鍵の身元を保証する基盤はどれか。", options: ["PKI", "FIDO", "SIEM", "EMM"], answer: 0, explain: "PKIが公開鍵基盤です。" },
    { id: 1128, chapter: 11, text: "パスワード不要の認証規格はどれか。", options: ["FIDO", "PKI", "SIEM", "TKIP"], answer: 0, explain: "FIDOがパスワードレス認証規格です。" },
    { id: 1129, chapter: 11, text: "状況に応じて認証強度を変える方式はどれか。", options: ["多要素認証", "多段階認証", "リスクベース認証", "シングルサインオン"], answer: 2, explain: "リスクベース認証が状況判断します。" },
    { id: 1130, chapter: 11, text: "信頼せず常に検証するモデルは何というか。", options: ["シングルサインオン", "ベースラインアプローチ", "ゼロトラストネットワーク", "詳細リスク分析"], answer: 2, explain: "ゼロトラストが信頼しないモデルです。" },

    // --- 第12章 IoTシステム (30問) ---
    { id: 1201, chapter: 12, text: "機械同士の通信を何と呼ぶか。", options: ["IoT", "M2M", "V2X", "EMM"], answer: 1, explain: "M2M(Machine to Machine)です。" },
    { id: 1202, chapter: 12, text: "専用構築で他連携が難しいシステム形態はどれか。", options: ["水平統合型", "垂直統合型", "エッジコンピューティング", "共通プラットフォーム"], answer: 1, explain: "垂直統合型はサイロ化しやすいです。" },
    { id: 1203, chapter: 12, text: "共通機能を提供する基盤は何か。", options: ["IoTゲートウェイ", "共通サービスプラットフォーム", "開発用ハード", "エッジコンピューティング"], answer: 1, explain: "共通サービスプラットフォームが基盤です。" },
    { id: 1204, chapter: 12, text: "IoT国際標準プロジェクトは何か。", options: ["IEEE", "3GPP", "oneM2M", "IETF"], answer: 2, explain: "oneM2Mが国際標準です。" },
    { id: 1205, chapter: 12, text: "分野を超えてデータを連携する考えは何か。", options: ["垂直統合", "水平方向の連携", "スタンドアロン", "セキュリティ・バイ・デザイン"], answer: 1, explain: "水平方向の連携が価値を生みます。" },
    { id: 1206, chapter: 12, text: "アプリ層が担う役割はどれか。", options: ["デバイス層", "ゲートウェイ層", "サービス提供層", "IoTアプリケーション"], answer: 3, explain: "アプリケーション層が価値を提供します。" },
    { id: 1207, chapter: 12, text: "デバイスの管理やデータ流通を担うのはどれか。", options: ["IoTデバイス", "IoTゲートウェイ", "IoTサービスプラットフォーム", "エッジノード"], answer: 2, explain: "サービスプラットフォームが中核です。" },
    { id: 1208, chapter: 12, text: "モバイル回線利用のIoT通信規格総称は何か。", options: ["V2X", "MTC", "RedCap", "eCall"], answer: 1, explain: "MTC(Machine Type Communication)です。" },
    { id: 1209, chapter: 12, text: "ウェアラブル向けLTE IoT規格は何か。", options: ["NB-IoT", "eMTC", "RedCap", "LPWA"], answer: 1, explain: "eMTC(LTE-M)です。" },
    { id: 1210, chapter: 12, text: "スマートメーター向けの超低消費電力LTE規格はどれか。", options: ["eMTC", "NB-IoT", "V2X", "NG-eCall"], answer: 1, explain: "NB-IoTが超低消費電力です。" },
    { id: 1211, chapter: 12, text: "自動車が周囲と通信する技術は何というか。", options: ["MTC", "LPWA", "V2X", "MQTT"], answer: 2, explain: "V2Xは車とモノの通信技術です。" },
    { id: 1212, chapter: 12, text: "自動緊急通報システムは何というか。", options: ["V2X", "eCall", "RedCap", "oneM2M"], answer: 1, explain: "eCallが自動緊急通報です。" },
    { id: 1213, chapter: 12, text: "IPパケット対応の次世代緊急通報は何か。", options: ["NG-eCall", "V2X", "eRedCap", "NB-IoT"], answer: 0, explain: "NG-eCallが次世代通報です。" },
    { id: 1214, chapter: 12, text: "5Gの機能を削減し中程度の速度を得る規格は何か。", options: ["NB-IoT", "eMTC", "RedCap", "eCall"], answer: 2, explain: "RedCapが5Gの軽量規格です。" },
    { id: 1215, chapter: 12, text: "RedCapの機能をさらに拡張（削減）した規格は何か。", options: ["eRedCap", "NG-eCall", "V2X", "oneM2M"], answer: 0, explain: "eRedCapが広域向け拡張規格です。" },
    { id: 1216, chapter: 12, text: "省電力広域通信技術の総称は何か。", options: ["V2X", "LPWA", "RedCap", "MQTT"], answer: 1, explain: "LPWAが省電力広域無線です。" },
    { id: 1217, chapter: 12, text: "データを中継する機器は何か。", options: ["IoTゲートウェイ", "開発ハード", "エッジサーバー", "ウェアラブル"], answer: 0, explain: "IoTゲートウェイが中継します。" },
    { id: 1218, chapter: 12, text: "環境情報をデジタル化する末端機器は何か。", options: ["IoTゲートウェイ", "IoTデバイス", "クラウド", "エッジコンピューティング"], answer: 1, explain: "IoTデバイスがデータ収集します。" },
    { id: 1219, chapter: 12, text: "アイデアを短期間で形にするマイコンボードは何か。", options: ["プロトタイピングボード", "IoTゲートウェイ", "ウェアラブル", "V2X"], answer: 0, explain: "プロトタイピングボードが開発の試作機です。" },
    { id: 1220, chapter: 12, text: "身につけて利用するIoTは何か。", options: ["ウェアラブルデバイス", "プロトタイピング", "エッジデバイス", "LPWA"], answer: 0, explain: "ウェアラブルデバイスです。" },
    { id: 1221, chapter: 12, text: "Web利用だが低電力IoTに不向きなプロトコルはどれ。", options: ["HTTP", "MQTT", "CoAP", "XMPP"], answer: 0, explain: "HTTPはオーバーヘッドが大きいです。" },
    { id: 1222, chapter: 12, text: "UDPベースで低負荷なIoT用プロトコルはどれ。", options: ["CoAP", "MQTT", "WebSocket", "XMPP"], answer: 0, explain: "CoAPが軽量プロトコルです。" },
    { id: 1223, chapter: 12, text: "出版・購読モデルのIoT事実上標準はどれ。", options: ["HTTP", "MQTT", "WebSocket", "XMPP"], answer: 1, explain: "MQTTがIoTの標準です。" },
    { id: 1224, chapter: 12, text: "XMLベースのチャット用プロトコルは何か。", options: ["XMPP", "MQTT", "CoAP", "HTTP"], answer: 0, explain: "XMPPがXMLベースのプロトコルです。" },
    { id: 1225, chapter: 12, text: "Webブラウザで双方向通信を行う技術はどれ。", options: ["WebSocket", "MQTT", "CoAP", "XMPP"], answer: 0, explain: "WebSocketがリアルタイム双方向です。" },
    { id: 1226, chapter: 12, text: "端末に近い場所で処理を行う仕組みは何か。", options: ["エッジコンピューティング", "垂直統合", "セキュリティ・バイ・デザイン", "プロトタイピング"], answer: 0, explain: "エッジコンピューティングが末端処理です。" },
    { id: 1227, chapter: 12, text: "設計段階からセキュリティを考慮する考えはどれ。", options: ["セキュリティ・バイ・デザイン", "水平方向の連携", "エッジコンピューティング", "プロトタイピング"], answer: 0, explain: "セキュリティ・バイ・デザインです。" },
    { id: 1228, chapter: 12, text: "漁業での活用事例は何か。", options: ["ブイによる水温監視", "ドローンで農薬", "ヘルメットで転倒検知", "ベッドセンサー"], answer: 0, explain: "海洋データの収集が漁業DXです。" },
    { id: 1229, chapter: 12, text: "医療・災害の活用事例の組み合わせはどれ。", options: ["バイタル遠隔監視と水位センサー", "トラクター自動化と工場監視", "漁船管理と重機管理", "ハウス管理と空調最適化"], answer: 0, explain: "遠隔監視と水位警報が典型例です。" },
    { id: 1230, chapter: 12, text: "IoT導入の課題は何か。", options: ["セキュリティ対策", "利益が出る", "永久メンテナンス不要", "データ独占"], answer: 0, explain: "セキュリティ対策が重要です。" },

    // --- 第13章 アプリと事例 (30問) ---
    { id: 1301, chapter: 13, text: "企業同士の電子商取引はどれか。", options: ["B2C", "B2B", "C2C", "B2G"], answer: 1, explain: "B2Bが企業間取引です。" },
    { id: 1302, chapter: 13, text: "企業から消費者への電子商取引はどれか。", options: ["B2C", "B2B", "B2G", "C2C"], answer: 0, explain: "B2Cが企業・消費者間取引です。" },
    { id: 1303, chapter: 13, text: "政府との電子調達などの取引はどれか。", options: ["B2E", "B2C", "B2G", "C2C"], answer: 2, explain: "B2Gが企業・行政間取引です。" },
    { id: 1304, chapter: 13, text: "企業から従業員へのサービス提供はどれか。", options: ["B2G", "B2B", "C2C", "B2E"], answer: 3, explain: "B2Eが企業・従業員間取引です。" },
    { id: 1305, chapter: 13, text: "消費者同士の取引はどれか。", options: ["C2C", "B2B", "B2C", "O2O"], answer: 0, explain: "C2Cが消費者間取引です。" },
    { id: 1306, chapter: 13, text: "モール経由で消費者に売る形態はどれか。", options: ["B2B2C", "O2O", "D2C", "OMO"], answer: 0, explain: "B2B2Cがモール型モデルです。" },
    { id: 1307, chapter: 13, text: "ネットで店舗への来店を促す手法はどれか。", options: ["O2O", "C2C", "D2C", "B2B"], answer: 0, explain: "O2Oがオンラインからオフラインへの誘導です。" },
    { id: 1308, chapter: 13, text: "メーカーが直接消費者に売るモデルはどれか。", options: ["O2O", "B2G", "D2C", "B2B2C"], answer: 2, explain: "D2Cが直接販売モデルです。" },
    { id: 1309, chapter: 13, text: "ネットとリアルを融合させる概念は何か。", options: ["B2B", "OMO", "B2E", "O2O"], answer: 1, explain: "OMOがネットとリアルの融合です。" },
    { id: 1310, chapter: 13, text: "ブラウザでアプリをすぐ利用するクラウド形態は何か。", options: ["PaaS", "IaaS", "SaaS", "DaaS"], answer: 2, explain: "SaaSがWebアプリ利用形態です。" },
    { id: 1311, chapter: 13, text: "アプリ開発プラットフォームを提供するクラウドはどれか。", options: ["SaaS", "PaaS", "IaaS", "MaaS"], answer: 1, explain: "PaaSが開発基盤です。" },
    { id: 1312, chapter: 13, text: "インフラ資源そのものを貸し出すクラウドはどれか。", options: ["SaaS", "PaaS", "IaaS", "CaaS"], answer: 2, explain: "IaaSがインフラ貸し出し型です。" },
    { id: 1313, chapter: 13, text: "組織の情報共有支援ソフトは何というか。", options: ["グループウェア", "マネージド・サービス", "基幹システム", "フィールドシステム"], answer: 0, explain: "グループウェアが共有支援ソフトです。" },
    { id: 1314, chapter: 13, text: "企業のビジネス根幹を支える重要システムはどれか。", options: ["基幹システム", "サブシステム", "業務システム", "オープンシステム"], answer: 0, explain: "基幹システムがビジネスの根幹です。" },
    { id: 1315, chapter: 13, text: "特定の業務効率化を目的としたシステムはどれか。", options: ["基幹システム", "マネージド・サービス", "業務システム", "グループウェア"], answer: 2, explain: "業務システムが効率化を担います。" },
    { id: 1316, chapter: 13, text: "保守・配送現場を支援するシステムは何というか。", options: ["学習システム", "基幹システム", "フィールド業務システム", "B2B"], answer: 2, explain: "フィールド業務支援システムです。" },
    { id: 1317, chapter: 13, text: "場所を問わず研修を受けられるシステムはどれか。", options: ["フィールドシステム", "モバイル・ラーニングシステム", "マネージド・サービス", "検索エンジン"], answer: 1, explain: "モバイル・ラーニングが研修支援システムです。" },
    { id: 1318, chapter: 13, text: "運用保守を専門業者に代行させるサービスはどれか。", options: ["ラーニングシステム", "フィールドシステム", "モバイルマネージド・サービス", "B2G"], answer: 2, explain: "モバイルマネージド・サービスが代行です。" },
    { id: 1319, chapter: 13, text: "メッセージ交換を行うコミュニケーションツールはどれか。", options: ["検索エンジン", "メッセージサービス", "Webミーティング", "基幹システム"], answer: 1, explain: "メッセージサービスが対話ツールです。" },
    { id: 1320, chapter: 13, text: "SNS等、相互コミュニケーションを形成するメディアは何か。", options: ["ソーシャルメディア", "グループウェア", "検索エンジン", "基幹システム"], answer: 0, explain: "ソーシャルメディアが共有メディアです。" },
    { id: 1321, chapter: 13, text: "離れた場所で映像と資料を共有し会議するツールはどれか。", options: ["ソーシャルメディア", "メッセージサービス", "Webミーティング", "ラーニングシステム"], answer: 2, explain: "Webミーティングが遠隔会議ツールです。" },
    { id: 1322, chapter: 13, text: "人間が手作業でリンク集を作る検索エンジン方式はどれか。", options: ["ロボット型", "ディレクトリ型", "メタ検索型", "ソーシャル型"], answer: 1, explain: "ディレクトリ型は手作業の分類です。" },
    { id: 1323, chapter: 13, text: "プログラムでページを巡回収集する現在の主流検索方式はどれか。", options: ["ディレクトリ型", "カテゴリ型", "ロボット型", "OMO型"], answer: 2, explain: "ロボット型が自動収集の主流です。" },
    { id: 1324, chapter: 13, text: "検索エンジン上位表示のための最適化は何というか。", options: ["SaaS", "O2O", "D2C", "SEO"], answer: 3, explain: "SEOが上位表示のための最適化です。" },
    { id: 1325, chapter: 13, text: "重機の遠隔監視はモバイルと何の活用事例か。", options: ["IoT", "SEO", "検索エンジン", "B2B"], answer: 0, explain: "IoTによる遠隔監視の代表例です。" },
    { id: 1326, chapter: 13, text: "モバイルシステムが推進する変化はどれか。", options: ["業務改革・社会変革", "電話の完全代替", "B2Cへの統合", "ディレクトリ回帰"], answer: 0, explain: "業務改革と社会変革を推進しています。" },
    { id: 1327, chapter: 13, text: "電子書籍や音楽配信を総称して何というか。", options: ["マネージド・サービス", "コンテンツサービス", "ラーニングシステム", "基幹システム"], answer: 1, explain: "コンテンツサービスです。" },
    { id: 1328, chapter: 13, text: "サブスク等、モバイル前提の事業構造を何と呼ぶか。", options: ["グループウェア", "IaaS", "ビジネスモデル", "SEO"], answer: 2, explain: "新しいビジネスモデルが誕生しています。" },
    { id: 1329, chapter: 13, text: "配車アプリ等で核となるのは何か。", options: ["位置情報の活用", "SEO", "ディレクトリ検索", "B2B取引"], answer: 0, explain: "位置情報の活用がモバイルアプリの核です。" },
    { id: 1330, chapter: 13, text: "複数のサービスを連携させて利便性を高める仕組みはどれか。", options: ["サービス孤立化", "アプリケーション連携", "ディレクトリ登録", "回線統合"], answer: 1, explain: "アプリケーション連携がシームレスな体験を作ります。" }
];